CREATE TABLE public."UserMovieLibrary" (
    id text NOT NULL,
    "userId" text NOT NULL,
    "movieId" text NOT NULL,
    status public."WatchingStatus" DEFAULT 'WANT_TO_WATCH'::public."WatchingStatus" NOT NULL,
    "watchCount" integer DEFAULT 0 NOT NULL,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL
);


ALTER TABLE public."UserMovieLibrary" OWNER TO postgres;

--
-- Name: UserMusicLibrary; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public."UserMusicLibrary" (
    id text NOT NULL,
    "userId" text NOT NULL,
    "musicId" text NOT NULL,
    status public."ListeningStatus" DEFAULT 'WANT_TO_LISTEN'::public."ListeningStatus" NOT NULL,
    "playCount" integer DEFAULT 0 NOT NULL,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL
);


ALTER TABLE public."UserMusicLibrary" OWNER TO postgres;

--
-- Name: UserPoints; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public."UserPoints" (
    id text NOT NULL,
    "userId" text NOT NULL,
    "totalPoints" integer DEFAULT 0 NOT NULL,
    "todayPoints" integer DEFAULT 0 NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL
);


ALTER TABLE public."UserPoints" OWNER TO postgres;

--
-- Name: Wallet; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public."Wallet" (
    id text NOT NULL,
    "userId" text NOT NULL,
    balance numeric(10,2) DEFAULT 0 NOT NULL,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL
);


ALTER TABLE public."Wallet" OWNER TO postgres;

--
-- Name: WalletTransaction; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public."WalletTransaction" (
    id text NOT NULL,
    "walletId" text NOT NULL,
    amount numeric(10,2) NOT NULL,
    type text NOT NULL,
    description text,
    "relatedType" text,
    "relatedId" text,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);


ALTER TABLE public."WalletTransaction" OWNER TO postgres;

--
-- Name: content_tags_deprecated; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.content_tags_deprecated (
    id text NOT NULL,
    "tagId" text NOT NULL,
    "diaryId" text,
    "homeworkId" text,
    "noteId" text,
    "readingLogId" text,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "movieLogId" text,
    "musicLogId" text
);


ALTER TABLE public.content_tags_deprecated OWNER TO postgres;

--
-- Name: tags_deprecated; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.tags_deprecated (
    id text NOT NULL,
    name text NOT NULL,
    color text,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);


ALTER TABLE public.tags_deprecated OWNER TO postgres;

