dius: 2px;\n            overflow: hidden;\n        }\n        \n        .stat-fill {\n            height: 100%;\n            border-radius: 2px;\n            transition: width 0.3s ease;\n        }\n        \n        .stat-fill.hunger {\n            background-color: #FF5722;\n        }\n        \n        .stat-fill.happiness {\n            background-color: #FFC107;\n        }\n        \n        .stat-fill.energy {\n            background-color: #2196F3;\n        }\n        \n        .stat-fill.health {\n            background-color: #4CAF50;\n        }\n        \n        .pet-name {\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            margin: 5px 0;\n        }\n        \n        .pet-name input {\n            background-color: white;\n            border: 1px solid #ddd;\n            border-radius: 15px;\n            padding: 5px 15px;\n            font-size: 16px;\n            text-align: center;\n            color: #333;\n        }\n        \n        .game-container {\n            position: relative;\n            width: 90%;\n            max-width: 500px;\n            height: 400px;\n            background-color: rgba(255, 255, 255, 0.3);\n            border-radius: 20px;\n            margin: 10px auto;\n            overflow: hidden;\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.2);\n            touch-action: none;\n        }\n        \n        .environment {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n        }\n        \n        .sky {\n            position: absolute;\n            top: 0;\n            width: 100%;\n            height: 70%;\n            background: linear-gradient(to bottom, #87CEEB, #B3E5FC);\n            overflow: hidden;\n        }\n        \n        .cloud {\n            position: absolute;\n            background-color: white;\n            border-radius: 50px;\n            opacity: 0.8;\n        }\n        \n        .cloud:before,\n        .cloud:after {\n            content: '';\n            position: absolute;\n            background-color: white;\n            border-radius: 50px;\n        }\n        \n        .cloud1 {\n            width: 50px;\n            height: 20px;\n            top: 20%;\n            left: 20%;\n            animation: drift 30s infinite;\n        }\n        \n        .cloud1:before {\n            width: 25px;\n            height: 25px;\n            top: -10px;\n            left: 10px;\n        }\n        \n        .cloud1:after {\n            width: 30px;\n            height: 20px;\n            top: -5px;\n            right: 10px;\n        }\n        \n        .weather-change {\n            position: absolute;\n            width: 30px;\n            height: 30px;\n            top: 15%;\n            right: 10%;\n            cursor: pointer;\n            font-size: 24px;\n            z-index: 20;\n        }\n        \n        @keyframes drift {\n            0% { left: -60px; }\n            100% { left: 100%; }\n        }\n        \n        .ground {\n            position: absolute;\n            bottom: 0;\n            width: 100%;\n            height: 30%;\n            background: linear-gradient(to bottom, #8BC34A, #689F38);\n            border-top: 3px solid #558B2F;\n        }\n        \n        .grass {\n            position: absolute;\n            bottom: 30%;\n            width: 100%;\n            height: 10px;\n            background-color: #4CAF50;\n        }\n        \n        .pet {\n            position: absolute;\n            width: 120px;\n            height: 120px;\n            bottom: calc(30% + 10px);\n            left: 50%;\n            transform: translateX(-50%);\n            cursor: pointer;\n            transition: all 0.3s ease;\n            z-index: 10;\n        }\n        \n        .pet-body {\n            width: 100px;\n            height: 80px;\n            background: linear-gradient(135deg, #FF9800, #F