 border-top: none;\n            border-radius: 0 0 20px 20px;\n            bottom: 15px;\n            left: 50%;\n            transform: translateX(-50%);\n        }\n        \n        .pet-tail {\n            position: absolute;\n            width: 60px;\n            height: 15px;\n            background: linear-gradient(135deg, #FF9800, #FF5722);\n            border-radius: 50%;\n            right: -40px;\n            top: 30px;\n            transform-origin: left center;\n            animation: wag 2s infinite;\n        }\n        \n        @keyframes wag {\n            0%, 100% { transform: rotate(10deg); }\n            50% { transform: rotate(-10deg); }\n        }\n        \n        .pet-sick .pet-body {\n            filter: grayscale(50%);\n            opacity: 0.8;\n        }\n        \n        .pet-sick .pet-tail {\n            animation: none;\n            transform: rotate(0deg);\n        }\n        \n        .pet-happy .pet-body {\n            animation: bounce 0.5s ease;\n        }\n        \n        .pet-happy .pet-mouth {\n            width: 30px;\n            height: 15px;\n            border-radius: 0 0 40px 40px;\n        }\n        \n        @keyframes bounce {\n            0%, 100% { transform: scale(1); }\n            50% { transform: scale(1.05); }\n        }\n        \n        .pet-sick .pet-mouth {\n            border-radius: 0;\n            transform: translateX(-50%) rotate(180deg);\n        }\n        \n        .pet-mood {\n            position: absolute;\n            top: -50px;\n            left: 50%;\n            transform: translateX(-50%);\n            font-size: 30px;\n            opacity: 0;\n            transition: opacity 0.3s ease;\n            white-space: nowrap;\n        }\n        \n        .pet:hover .pet-mood {\n            opacity: 1;\n        }\n        \n        .pet-thought {\n            position: absolute;\n            top: -100px;\n            left: 50%;\n            transform: translateX(-50%);\n            background-color: white;\n            padding: 10px 15px;\n            border-radius: 15px;\n            font-size: 16px;\n            color: #333;\n            opacity: 0;\n            transition: opacity 0.3s ease;\n            white-space: nowrap;\n            box-shadow: 0 2px 5px rgba(0, 0, 0, 0.2);\n            z-index: 20;\n            max-width: 150px;\n            text-align: center;\n        }\n        \n        .pet-thought:after {\n            content: '';\n            position: absolute;\n            bottom: -10px;\n            left: 50%;\n            transform: translateX(-50%);\n            border-width: 10px 10px 0;\n            border-style: solid;\n            border-color: white transparent transparent;\n        }\n        \n        .pet:hover .pet-thought {\n            opacity: 1;\n        }\n        \n        .pet-status {\n            position: absolute;\n            top: 10px;\n            right: 10px;\n            background-color: rgba(255, 255, 255, 0.8);\n            padding: 5px 10px;\n            border-radius: 10px;\n            font-size: 14px;\n            font-weight: bold;\n        }\n        \n        .pet-status.healthy {\n            color: #4CAF50;\n        }\n        \n        .pet-status.sick {\n            color: #F44336;\n        }\n        \n        .pet-status.tired {\n            color: #FF9800;\n        }\n        \n        .action-panel {\n            background-color: white;\n            border-radius: 15px;\n            padding: 15px;\n            margin: 10px auto;\n            max-width: 500px;\n            box-shadow: 0 3px 10px rgba(0, 0, 0, 0.1);\n        }\n        \n        .action-buttons {\n            display: flex;\n            justify-content: space-around;\n            gap: 10px;\n            margin-bottom: 15px;\n            flex-wrap: wrap;\n        }\n        \n        .action-btn {\n            background-color: #4CAF50;\n            color: white;\n            border: none;\n            padding: 12px 18px;\n            border-radius: 25px;\n            font-size: 16px;\n            cursor: pointer;\n            box-shadow: 0 3px 5px rgba(0, 0, 0, 0.2);\n            transition: all 0.3s ease;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            gap: 5px;\n            min-width: 90px;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .action-btn:before {\n            content: '';\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            background-color: rgba(255, 255, 255, 0.3);\n            transform: translateY(-100%);\n            transition: transform 0.5s ease;\n        }\n        \n        .action-btn:hover:before {\n            transform: translateY(0);\n        }\n        \n        .action-btn:hover, .action-btn:focus {\n            transform: translateY(-2px);\n            box-shadow: 0 5px 8px rgba(0, 0, 0, 0.3);\n        }\n        \n        .action-btn:active {\n            transform: translateY(0);\n        }\n        \n        .action-btn:disabled {\n            background-color: #9E9E9E;\n            cursor: not-allowed;\n        }\n        \n        .action-btn:disabled:before {\n            display: none;\n        }\n        \n        .cooldown {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            background-color: rgba(0, 0, 0, 0.3);\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            border-radius: 25px;\n            color: white;\n            font-weight: bold;\n        }\n        \n        .message {\n            position: fixed;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            background-color: rgba(255, 255, 255, 0.95);\n            padding: 20px 30px;\n            border-radius: 15px;\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);\n            font-size: 18px;\n            color: #333;\n            opacity: 0;\n            pointer-events: none;\n            transition: opacity 0.3s ease;\n            z-index: 100;\n            text-align: center;\n            max-width: 80%;\n        }\n        \n        .message.show {\n            opacity: 1;\n            pointer-events: auto;\n        }\n        \n        .food {\n            position: absolute;\n            width: 30px;\n            height: 30px;\n            background: radial-gradient(circle, #FFC107, #FF9800);\n            border-radius: 50%;\n            bottom: calc(30% + 10px);\n            box-shadow: 0 3px 5px rgba(0, 0, 0, 0.3);\n            z-index: 5;\n            cursor: pointer;\n        }\n        \n        .food:before {\n            content: '';\n            position: absolute;\n            width: 10px;\n            height: 5px;\n            background-color: #8BC34A;\n            top: -5px;\n            left: 50%;\n            transform: translateX(-50%);\n            border-radius: 50% 50% 0 0;\n        }\n        \n        .toy {\n            position: absolute;\n            width: 40px;\n            height: 40px;\n            background: radial-gradient(circle, #E91E63, #9C27B0);\n            border-radius: 50%;\n            bottom: calc(30% + 10px);\n            box-shadow: 0 3px 5px rgba(0, 0, 0, 0.3);\n            z-index: 5;\n            cursor: pointer;\n        }\n        \n        .toy:before {\n            content: '';\n            position: absolute;\n            width: 10px;\n            height: 20px;\n            background-color: #FFC107;\n            top: -10px;\n            left: 50%;\n            transform: translateX(-50%);\n        }\n        \n        .toy:after {\n            content: '';\n            position: absolute;\n            width: 20px;\n            height: 10px;\n            background-color: #FFC107;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n        }\n        \n        .pet-sleeping {\n            animation: sleep-breathe 3s infinite;\n        }\n        \n        @keyframes sleep-breathe {\n            0%, 100% { transform: translateX(-50%) scale(1); }\n            50% { transform: translateX(-50%) scale(1.02); }\n        }\n        \n        .pet-sleeping .pet-eye {\n            height: 3px;\n        }\n        \n        .pet-sleeping .pupil {\n            height: 3px;\n            border-radius: 0;\n        }\n        \n        .zzz {\n            position: absolute;\n            top: -30px;\n            left: 50%;\n            transform: translateX(-50%);\n            font-size: 20px;\n            color: #1976D2;\n            opacity: 0;\n        }\n        \n        .pet-sleeping .zzz {\n            opacity: 1;\n            animation: float-z 2s infinite;\n        }\n        \n        @keyframes float-z {\n            0% { opacity: 0; transform: translateX(-50%) translateY(0); }\n            50% { opacity: 1; transform: translateX(-50%) translateY(-10px); }\n            100% { opacity: 0; transform: translateX(-50%) translateY(-20px); }\n        }\n        \n        .pet-eating {\n            animation: eat 0.5s ease;\n        }\n        \n        @keyframes eat {\n            0%, 100% { transform: translateX(-50%) rotate(0); }\n            25% { transform: translateX(-50%) rotate(-5deg); }\n            75% { transform: translateX(-50%) rotate(5deg); }\n        }\n        \n        .pet-playing {\n            animation: play 1s ease;\n        }\n        \n        @keyframes play {\n            0%, 100% { transform: translateX(-50%) rotate(0); }\n            25% { transform: translateX(-50%) translateX(-30px) rotate(-5deg); }\n            75% { transform: translateX(-50%) translateX(30px) rotate(5deg); }\n        }\n        \n        .pet-shower {\n            position: absolute;\n            width: 150px;\n            height: 150px;\n            bottom: calc(30% - 30px);\n            left: 50%;\n            transform: translateX(-50%);\n            pointer-events: none;\n            z-index: 15;\n        }\n        \n        .water-drop {\n            position: absolute;\n            width: 5px;\n            height: 20px;\n            background: radial-gradient(circle, rgba(33, 150, 243, 0.8), rgba(33, 150, 243, 0.4));\n            border-radius: 50% 50% 50% 50% / 60% 60% 40% 40%;\n            animation: fall 1s linear infinite;\n        }\n        \n        @keyframes fall {\n            0% { transform: translateY(-20px); opacity: 0; }\n            50% { opacity: 1; }\n            100% { transform: translateY(150px); opacity: 0; }\n        }\n        \n        .medicine {\n            position: absolute;\n            width: 40px;\n            height: 40px;\n            background: radial-gradient(circle, #9C27B0, #673AB7);\n            border-radius: 50%;\n            bottom: calc(30% + 10px);\n            box-shadow: 0 3px 5px rgba(0, 0, 0, 0.3);\n            z-index: 5;\n            cursor: pointer;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 20px;\n        }\n        \n        .vitamin {\n            position: absolute;\n            width: 35px;\n            height: 35px;\n            background: radial-gradient(circle, #FFEB3B, #FFC107);\n            border-radius: 50%;\n            bottom: calc(30% + 10px);\n            box-shadow: 0 3px 5px rgba(0, 0, 0, 0.3);\n            z-index: 5;\n            cursor: pointer;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 20px;\n        }\n        \n        .temperature {\n            position: absolute;\n            bottom: 10px;\n            left: 10px;\n            background-color: rgba(255, 255, 255, 0.8);\n            padding: 5px 10px;\n            border-radius: 10px;\n            font-size: 14px;\n            font-weight: bold;\n        }\n        \n        .temperature.hot {\n            color: #F44336;\n        }\n        \n        .temperature.normal {\n            color: #4CAF50;\n        }\n        \n        .temperature.cold {\n            color: #2196F3;\n        }\n        \n        .weather-effect {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            pointer-events: none;\n            z-index: 5;\n        }\n        \n        .rain {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            background: linear-gradient(to bottom, transparent, rgba(255, 255, 255, 0.1));\n            opacity: 0;\n            transition: opacity 0.5s ease;\n        }\n        \n        .rain.active {\n            opacity: 1;\n            animation: rain-fall 0.5s linear infinite;\n        }\n        \n        @keyframes rain-fall {\n            0% { background-position: 0 0; }\n            100% { background-position: 0 10px; }\n        }\n        \n        .snow {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            opacity: 0;\n            transition: opacity 0.5s ease;\n        }\n        \n        .snow.active {\n            opacity: 1;\n        }\n        \n        .snowflake {\n            position: absolute;\n            color: white;\n            font-size: 20px;\n            animation: snow-fall 5s linear infinite;\n        }\n        \n        @keyframes snow-fall {\n            0% { transform: translateY(-20px); opacity: 0; }\n            10% { opacity: 1; }\n            90% { opacity: 1; }\n            100% { transform: translateY(400px); opacity: 0; }\n        }\n        \n        .sun {\n            position: absolute;\n            top: 20px;\n            right: 20px;\n            width: 60px;\n            height: 60px;\n            background: radial-gradient(circle, #FFEB3B, #FFC107);\n            border-radius: 50%;\n            box-shadow: 0 0 20px rgba(255, 235, 59, 0.8);\n            opacity: 0;\n            transition: opacity 0.5s ease;\n        }\n        \n        .sun.active {\n            opacity: 1;\n        }\n        \n        .event-notification {\n            position: fixed;\n            top: 20px;\n            left: 50%;\n            transform: translateX(-50%);\n            background-color: rgba(255, 255, 255, 0.9);\n            padding: 15px 25px;\n            border-radius: 10px;\n            box-shadow: 0 3px 10px rgba(0, 0, 0, 0.2);\n            font-size: 16px;\n            color: #333;\n            opacity: 0;\n            transition: opacity 0.3s ease;\n            z-index: 200;\n            text-align: center;\n            max-width: 80%;\n        }\n        \n        .event-notification.show {\n            opacity: 1;\n        }\n        \n        .weather-panel {\n            position: absolute;\n            top: 20px;\n            left: 20px;\n            background-color: rgba(255, 255, 255, 0.8);\n            padding: 10px;\n            border-radius: 10px;\n            display: flex;\n            gap: 10px;\n            z-index: 15;\n        }\n        \n        .weather-btn {\n            width: 40px;\n            height: 40px;\n            border: none;\n            background: none;\n            cursor: pointer;\n            font-size: 24px;\n            border-radius: 50%;\n            transition: all 0.3s ease;\n        }\n        \n        .weather-btn:hover {\n            background-color: rgba(0, 0, 0, 0.1);\n            transform: scale(1.1);\n        }\n        \n        .weather-btn.active {\n            background-color: rgba(76, 175, 80, 0.2);\n        }\n        \n        @media (max-width: 600px) {\n            h1 {\n                font-size: 20px;\n            }\n            \n            .stat {\n                font-size: 12px;\n                padding: 4px 8px;\n            }\n            \n            .action-btn {\n                font-size: 14px;\n                padding: 10px 12px;\n                min-width: 70px;\n            }\n            \n            .game-container {\n                height: 350px;\n            }\n        }\n    </style>\n</head>\n<body>\n    <div class="header">\n        <h1>我的虚拟宠物 - 真实养成体验</h1>\n        <div class="pet-name">\n            <input type="text" id="petNameInput" value="小可爱" placeholder="给宠物起个名字">\n        </div>\n        <div class="stats">\n            <div class="stat">\n                <span class="stat-icon">🍖</span>\n                饱食度: <span id="hunger">100</span>%\n                <div class="stat-bar">\n                    <div class="stat-fill hunger" id="hungerBar"></div>\n                </div>\n            </div>\n            <div class="stat">\n                <span class="stat-icon">😊</span>\n                快乐度: <span id="happiness">100</span>%\n                <div class="stat-bar">\n                    <div class="stat-fill happiness" id="happinessBar"></div>\n                </div>\n            </div>\n            <div class="stat">\n                <span class="stat-icon">⚡</span>\n                能量: <span id="energy">100</span>%\n                <div class="stat-bar">\n                    <div class="stat-fill energy" id="energyBar"></div>\n                </div>\n            </div>\n            <div class="stat">\n                <span class="stat-icon">❤️</span>\n                健康: <span id="health">100</span>%\n                <div class="stat-bar">\n                    <div class="stat-fill health" id="healthBar"></div>\n                </div>\n            </div>\n            <div class="stat">\n                <span class="stat-icon">🏅</span>\n                等级: <span id="level">1</span>\n            </div>\n        </div>\n    </div>\n    \n    <div class="game-container">\n        <div class="environment">\n            <div class="sky">\n                <div class="cloud cloud1"></div>\n            </div>\n            <div class="grass"></div>\n            <div class="ground"></div>\n            \n            <div class="weather-panel">\n                <button class="weather-btn" data-weather="normal" title="正常天气">☀️</button>\n                <button class="weather-btn" data-weather="hot" title="炎热天气">🔥</button>\n                <button class="weather-btn" data-weather="cold" title="寒冷天气">❄️</button>\n                <button class="weather-btn" data-weather="rain" title="下雨">🌧️</button>\n                <button class="weather-btn" data-weather="snow" title="下雪">❄️</button>\n            </div>\n            \n            <div class="temperature normal" id="temperature">温度: 25°C</div>\n            \n            <div class="weather-effect">\n                <div class="rain" id="rain"></div>\n                <div class="snow" id="snow"></div>\n                <div class="sun" id="sun"></div>\n            </div>\n        </div>\n        \n        <div class="pet-status healthy" id="petStatus">健康</div>\n        \n        <div class="pet" id="pet">\n            <div class="pet-mood">😊</div>\n            <div class="pet-thought">我好开心！</div>\n            <div class="zzz">Z z z</div>\n            <div class="pet-body">\n                <div class="pet-ear left"></div>\n                <div class="pet-ear right"></div>\n                <div class="pet-eye left">\n                    <div class="pupil"></div>\n                </div>\n                <div class="pet-eye right">\n                    <div class="pupil"></div>\n                </div>\n                <div class="pet-nose"></div>\n                <div class="pet-mouth"></div>\n                <div class="pet-tail"></div>\n            </div>\n            \n            <div class="pet-shower" id="shower" style="display: none;">\n                <!-- 雨滴将通过JS动态生成 -->\n            </div>\n        </div>\n    </div>\n    \n    <div class="action-panel">\n        <div class="action-buttons">\n            <button class="action-btn" id="feedBtn">\n                <span>🍖</span> 喂食\n            </button>\n            <button class="action-btn" id="playBtn">\n                <span>🎾</span> 玩耍\n            </button>\n            <button class="action-btn" id="sleepBtn">\n                <span>😴</span> 睡觉\n            </button>\n            <button class="action-btn" id="cleanBtn">\n                <span>🛁</span> 清洁\n            </button>\n            <button class="action-btn" id="medicineBtn">\n                <span>💊</span> 医药\n            </button>\n            <button class="action-btn" id="vitaminBtn">\n                <span>💊</span> 维生素\n            </button>\n        </div>\n    </div>\n    \n    <div class="message" id="message"></div>\n    <div class="event-notification" id="eventNotification"></div>\n    \n    <script>\n        document.addEventListener('DOMContentLoaded', () => {\n            // 游戏状态\n            const gameState = {\n                hunger: 100,\n                happiness: 100,\n                energy: 100,\n                health: 100,\n                level: 1,\n                isSleeping: false,\n                lastFed: Date.now(),\n                lastPlayed: Date.now(),\n                lastCleaned: Date.now(),\n                lastMedicine: Date.now(),\n                lastVitamin: Date.now(),\n                petName: "小可爱",\n                weather: "normal",\n                temperature: 25,\n                sicknessLevel: 0,\n                lastSickEvent: Date.now(),\n                isHot: false,\n                isCold: false,\n                lastWeatherChange: Date.now()\n            };\n            \n            // 宠物心情和想法\n            const petThoughts = {\n                happy: ["我好开心！", "今天真棒！", "我爱你！", "主人最好了！"],\n                hungry: ["我饿了...", "有没有吃的？", "肚子咕咕叫...", "我想吃零食！"],\n                sad: ["我好难过...", "陪我玩一下嘛", "抱抱我", "我需要关心"],\n                tired: ["我好困...", "想睡觉了", "需要休息", "我想睡觉了"],\n                sick: ["我不舒服...", "身体不舒服", "想休息", "带我看医生"],\n                hot: ["好热啊...", "我想凉快一下", "降温！"],\n                cold: ["好冷啊...", "我需要温暖", "抱抱我"]\n            };\n            \n            // 天气系统\n            const weatherEffects = {\n                normal: { health: 0, energy: 0, message: "天气舒适" },\n                hot: { health: -0.2, energy: -0.3, message: "天气炎热，宠物感到不适" },\n                cold: { health: -0.1, energy: -0.2, message: "天气寒冷，宠物感到不适" },\n                rain: { health: 0.1, energy: -0.1, message: "下雨了，空气清新" },\n                snow: { health: -0.3, energy: -0.4, message: "下雪了，太冷了！" }\n            };\n            \n            // DOM 元素\n            const pet = document.getElementById('pet');\n            const petMood = pet.querySelector('.pet-mood');\n            const petThought = pet.querySelector('.pet-thought');\n            const petStatus = document.getElementById('petStatus');\n            const message = document.getElementById('message');\n            const eventNotification = document.getElementById('eventNotification');\n            const petNameInput = document.getElementById('petNameInput');\n            const shower = document.getElementById('shower');\n            const temperature = document.getElementById('temperature');\n            const sun = document.getElementById('sun');\n            const rain = document.getElementById('rain');\n            const snow = document.getElementById('snow');\n            \n            // 状态显示元素\n            const hungerDisplay = document.getElementById('hunger');\n            const happinessDisplay = document.getElementById('happiness');\n            const energyDisplay = document.getElementById('energy');\n            const healthDisplay = document.getElementById('health');\n            const levelDisplay = document.getElementById('level');\n            \n            const hungerBar = document.getElementById('hungerBar');\n            const happinessBar = document.getElementById('happinessBar');\n            const energyBar = document.getElementById('energyBar');\n            const healthBar = document.getElementById('healthBar');\n            \n            // 按钮元素\n            const feedBtn = document.getElementById('feedBtn');\n            const playBtn = document.getElementById('playBtn');\n            const sleepBtn = document.getElementById('sleepBtn');\n            const cleanBtn = document.getElementById('cleanBtn');\n            const medicineBtn = document.getElementById('medicineBtn');\n            const vitaminBtn = document.getElementById('vitaminBtn');\n            \n            // 天气按钮\n            const weatherBtns = document.querySelectorAll('.weather-btn');\n            \n            // 更新宠物名字\n            petNameInput.addEventListener('input', (e) => {\n                gameState.petName = e.target.value || "小可爱";\n                updatePetStatus();\n            });\n            \n            // 天气切换\n            weatherBtns.forEach(btn => {\n                btn.addEventListener('click', () => {\n                    const weather = btn.getAttribute('data-weather');\n                    changeWeather(weather);\n                    \n                    weatherBtns.forEach(b => b.classList.remove('active'));\n                    btn.classList.add('active');\n                });\n            });\n            \n            // 更换天气\n            function changeWeather(weather) {\n                gameState.weather = weather;\n                gameState.lastWeatherChange = Date.now();\n                \n                // 重置所有天气效果\n                rain.classList.remove('active');\n                snow.classList.remove('active');\n                sun.classList.remove('active');\n                \n                switch(weather) {\n                    case 'normal':\n                        gameState.temperature = 25;\n                        gameState.isHot = false;\n                        gameState.isCold = false;\n                        break;\n                    case 'hot':\n                        gameState.temperature = 35;\n                        gameState.isHot = true;\n                        gameState.isCold = false;\n                        sun.classList.add('active');\n                        showEventNotification("天气变得炎热了！", "hot");\n                        break;\n                    case 'cold':\n                        gameState.temperature = 10;\n                        gameState.isHot = false;\n                        gameState.isCold = true;\n                        showEventNotification("天气变冷了！", "cold");\n                        break;\n                    case 'rain':\n                        gameState.isHot = false;\n                        gameState.isCold = false;\n                        rain.classList.add('active');\n                        showEventNotification("下雨了！记得给宠物避雨", "rain");\n                        break;\n                    case 'snow':\n                        gameState.temperature = -5;\n                        gameState.isHot = false;\n                        gameState.isCold = true;\n                        snow.classList.add('active');\n                        showEventNotification("下雪了！宠物可能会感冒", "snow");\n                        createSnowflakes();\n                        break;\n                }\n                \n                updateTemperatureDisplay();\n            }\n            \n            // 更新温度显示\n            function updateTemperatureDisplay() {\n                temperature.textContent = `温度: ${gameState.temperature}°C`;\n                temperature.className = 'temperature';\n                \n                if (gameState.temperature >= 30) {\n                    temperature.classList.add('hot');\n                } else if (gameState.temperature <= 15) {\n                    temperature.classList.add('cold');\n                } else {\n                    temperature.classList.add('normal');\n                }\n            }\n            \n            // 创建雪花\n            function createSnowflakes() {\n                const snowContainer = document.getElementById('snow');\n                snowContainer.innerHTML = '';\n                \n                for (let i = 0; i < 30; i++) {\n                    const snowflake = document.createElement('div');\n                    snowflake.className = 'snowflake';\n                    snowflake.textContent = '❄';\n                    snowflake.style.left = Math.random() * 100 + '%';\n                    snowflake.style.animationDelay = Math.random() * 5 + 's';\n                    snowflake.style.animationDuration = (5 + Math.random() * 5) + 's';\n                    snowContainer.appendChild(snowflake);\n                }\n            }\n            \n            // 显示事件通知\n            function showEventNotification(text, type) {\n                eventNotification.textContent = text;\n                eventNotification.classList.add('show');\n                \n                setTimeout(() => {\n                    eventNotification.classList.remove('show');\n                }, 3000);\n            }\n            \n            // 随机生病事件\n            function randomSicknessEvent() {\n                if (gameState.isSleeping) return;\n                \n                const now = Date.now();\n                if (now - gameState.lastSickEvent < 30000) return; // 30秒内不重复生病事件\n                \n                const sicknessChance = 0.01; // 1%的概率\n                \n                if (Math.random() < sicknessChance) {\n                    const reasons = [\n                        "吃了不干净的食物",\n                        "天气突然变化",\n                        "玩得太累了",\n                        "太久没洗澡",\n                        "接触了生病的动物"\n                    ];\n                    \n                    const reason = reasons[Math.floor(Math.random() * reasons.length)];\n                    gameState.sicknessLevel = 20;\n                    gameState.health -= 20;\n                    gameState.lastSickEvent = now;\n                    \n                    showEventNotification(`${gameState.petName}${reason}，生病了！`, "sick");\n                    updateDisplay();\n                }\n            }\n            \n            // 更新显示\n            function updateDisplay() {\n                hungerDisplay.textContent = Math.round(gameState.hunger);\n                happinessDisplay.textContent = Math.round(gameState.happiness);\n                energyDisplay.textContent = Math.round(gameState.energy);\n                healthDisplay.textContent = Math.round(gameState.health);\n                levelDisplay.textContent = gameState.level;\n                \n                // 更新进度条\n                hungerBar.style.width = `${gameState.hunger}%`;\n                happinessBar.style.width = `${gameState.happiness}%`;\n                energyBar.style.width = `${gameState.energy}%`;\n                healthBar.style.width = `${gameState.health}%`;\n                \n                updatePetMood();\n                updatePetThought();\n                updatePetStatus();\n                updatePetAppearance();\n                \n                // 检查升级\n                const totalStats = Math.floor((gameState.hunger + gameState.happiness + gameState.energy + gameState.health) / 4);\n                if (totalStats >= gameState.level * 25 && gameState.level < 10) {\n                    levelUp();\n                }\n                \n                // 随机生病事件\n                randomSicknessEvent();\n            }\n            \n            // 更新宠物心情\n            function updatePetMood() {\n                if (gameState.isSleeping) {\n                    petMood.textContent = '😴';\n                } else if (gameState.health < 30) {\n                    petMood.textContent = '🤒';\n                } else if (gameState.sicknessLevel > 0) {\n                    petMood.textContent = '🤢';\n                } else if (gameState.isHot) {\n                    petMood.textContent = '😅';\n                } else if (gameState.isCold) {\n                    petMood.textContent = '🥶';\n                } else if (gameState.hunger < 30) {\n                    petMood.textContent = '😟';\n                } else if (gameState.happiness < 30) {\n                    petMood.textContent = '😕';\n                } else if (gameState.energy < 30) {\n                    petMood.textContent = '😴';\n                } else if (gameState.hunger > 80 && gameState.happiness > 80 && gameState.energy > 80) {\n                    petMood.textContent = '😄';\n                } else {\n                    petMood.textContent = '😊';\n                }\n            }\n            \n            // 更新宠物想法\n            function updatePetThought() {\n                if (gameState.isSleeping) {\n                    petThought.textContent = 'Z z z...';\n                } else if (gameState.health < 30) {\n                    petThought.textContent = petThoughts.sick[Math.floor(Math.random() * petThoughts.sick.length)];\n                } else if (gameState.sicknessLevel > 0) {\n                    petThought.textContent = "我不舒服...";\n                } else if (gameState.isHot) {\n                    petThought.textContent = petThoughts.hot[Math.floor(Math.random() * petThoughts.hot.length)];\n                } else if (gameState.isCold) {\n                    petThought.textContent = petThoughts.cold[Math.floor(Math.random() * petThoughts.cold.length)];\n                } else if (gameState.hunger < 30) {\n                    petThought.textContent = petThoughts.hungry[Math.floor(Math.random() * petThoughts.hungry.length)];\n                } else if (gameState.happiness < 30) {\n                    petThought.textContent = petThoughts.sad[Math.floor(Math.random() * petThoughts.sad.length)];\n                } else if (gameState.energy < 30) {\n                    petThought.textContent = petThoughts.tired[Math.floor(Math.random() * petThoughts.tired.length)];\n                } else {\n                    petThought.textContent = petThoughts.happy[Math.floor(Math.random() * petThoughts.happy.length)];\n                }\n            }\n            \n            // 更新宠物状态\n            function updatePetStatus() {\n                petStatus.textContent = `${gameState.petName}的状态`;\n                \n                if (gameState.health < 30) {\n                    petStatus.textContent = `${gameState.petName}严重生病`;\n                    petStatus.classList.add('sick');\n                    petStatus.classList.remove('healthy', 'tired');\n                    pet.classList.add('pet-sick');\n                    pet.classList.remove('pet-tired');\n                } else if (gameState.sicknessLevel > 0) {\n                    petStatus.textContent = `${gameState.petName}轻微生病`;\n                    petStatus.classList.add('sick');\n                    petStatus.classList.remove('healthy', 'tired');\n                    pet.classList.add('pet-sick');\n                    pet.classList.remove('pet-tired');\n                } else if (gameState.energy < 30) {\n                    petStatus.textContent = `${gameState.petName}累了`;\n                    petStatus.classList.add('tired');\n                    petStatus.classList.remove('healthy', 'sick');\n                    pet.classList.add('pet-tired');\n                    pet.classList.remove('pet-sick');\n                } else {\n                    petStatus.textContent = `${gameState.petName}健康`;\n                    petStatus.classList.add('healthy');\n                    petStatus.classList.remove('sick', 'tired');\n                    pet.classList.remove('pet-sick', 'pet-tired');\n                }\n            }\n            \n            // 更新宠物外观\n            function updatePetAppearance() {\n                if (gameState.happiness > 80) {\n                    pet.classList.add('pet-happy');\n                } else {\n                    pet.classList.remove('pet-happy');\n                }\n                \n                if (gameState.isSleeping) {\n                    pet.classList.add('pet-sleeping');\n                } else {\n                    pet.classList.remove('pet-sleeping');\n                }\n            }\n            \n        // 显示消息\n        function showMessage(text, duration = 2000) {\n            message.textContent = text;\n            message.classList.add('show');\n            \n            setTimeout(() => {\n                message.classList.remove('show');\n            }, duration);\n        }\n        \n        // 创建食物\n        function createFood() {\n            const food = document.createElement('div');\n            food.className = 'food';\n            food.style.left = Math.random() * 70 + 15 + '%';\n            \n            // 随机生成不同的食物\n            const foods = ['🍖', '🥩', '🍗', '🥚', '🥛', '🍎', '🥕', '🍇'];\n            food.textContent = foods[Math.floor(Math.random() * foods.length)];\n            \n            pet.parentElement.appendChild(food);\n            \n            // 宠物吃食物\n            setTimeout(() => {\n                if (!gameState.isSleeping) {\n                    pet.classList.add('pet-eating');\n                    gameState.hunger = Math.min(100, gameState.hunger + 25);\n                    gameState.happiness = Math.min(100, gameState.happiness + 5);\n                    \n                    // 不同食物对健康的影响\n                    const foodTypes = ['🍖', '🥩', '🍗'];\n                    if (foodTypes.includes(food.textContent)) {\n                        gameState.health = Math.min(100, gameState.health + 3);\n                    } else {\n                        gameState.health = Math.max(0, gameState.health - 2);\n                    }\n                    \n                    updateDisplay();\n                    showMessage(`${gameState.petName}吃得好开心！😋`);\n                    \n                    setTimeout(() => {\n                        pet.classList.remove('pet-eating');\n                    }, 500);\n                }\n                \n                food.remove();\n            }, 500);\n        }\n        \n        // 创建玩具\n        function createToy() {\n            const toy = document.createElement('div');\n            toy.className = 'toy';\n            toy.style.left = Math.random() * 70 + 15 + '%';\n            \n            // 随机生成不同的玩具\n            const toys = ['🎾', '🎱', '🎲', '🎪', '🎨', '🎯'];\n            toy.textContent = toys[Math.floor(Math.random() * toys.length)];\n            \n            pet.parentElement.appendChild(toy);\n            \n            // 宠物玩玩具\n            setTimeout(() => {\n                if (!gameState.isSleeping && gameState.energy >= 20) {\n                    pet.classList.add('pet-playing');\n                    gameState.happiness = Math.min(100, gameState.happiness + 20);\n                    gameState.energy = Math.max(0, gameState.energy - 20);\n                    updateDisplay();\n                    showMessage(`${gameState.petName}玩得好开心！🎉`);\n                    \n                    setTimeout(() => {\n                        pet.classList.remove('pet-playing');\n                    }, 1000);\n                }\n                \n                toy.remove();\n            }, 500);\n        }\n        \n        // 创建医药\n        function createMedicine() {\n            const medicine = document.createElement('div');\n            medicine.className = 'medicine';\n            medicine.textContent = '💊';\n            medicine.style.left = Math.random() * 70 + 15 + '%';\n            \n            pet.parentElement.appendChild(medicine);\n            \n            // 宠物吃药\n            setTimeout(() => {\n                if (!gameState.isSleeping) {\n                    pet.classList.add('pet-happy');\n                    gameState.health = Math.min(100, gameState.health + 40);\n                    gameState.sicknessLevel = Math.max(0, gameState.sicknessLevel - 40);\n                    gameState.energy = Math.max(0, gameState.energy - 10);\n                    updateDisplay();\n                    showMessage(`${gameState.petName}吃了药，感觉好多了！🩺`);\n                    \n                    setTimeout(() => {\n                        pet.classList.remove('pet-happy');\n                    }, 1000);\n                }\n                \n                medicine.remove();\n            }, 500);\n        }\n        \n        // 创建维生素\n        function createVitamin() {\n            const vitamin = document.createElement('div');\n            vitamin.className = 'vitamin';\n            vitamin.textContent = '💪';\n            vitamin.style.left = Math.random() * 70 + 15 + '%';\n            \n            pet.parentElement.appendChild(vitamin);\n            \n            // 宠物吃维生素\n            setTimeout(() => {\n                if (!gameState.isSleeping) {\n                    pet.classList.add('pet-happy');\n                    gameState.health = Math.min(100, gameState.health + 15);\n                    gameState.energy = Math.min(100, gameState.energy + 15);\n                    gameState.happiness = Math.min(100, gameState.happiness + 10);\n                    updateDisplay();\n                    showMessage(`${gameState.petName}补充了维生素，更有活力了！💪`);\n                    \n                    setTimeout(() => {\n                        pet.classList.remove('pet-happy');\n                    }, 1000);\n                }\n                \n                vitamin.remove();\n            }, 500);\n        }\n        \n        // 创建雨滴效果\n        function createShower() {\n            shower.style.display = 'block';\n            shower.innerHTML = '';\n            \n            // 创建多个雨滴\n            for (let i = 0; i < 20; i++) {\n                setTimeout(() => {\n                    const drop = document.createElement('div');\n                    drop.className = 'water-drop';\n                    drop.style.left = Math.random() * 100 + '%';\n                    drop.style.animationDelay = Math.random() * 1 + 's';\n                    shower.appendChild(drop);\n                }, i * 50);\n            }\n        }\n        \n        // 升级\n        function levelUp() {\n            gameState.level++;\n            showEventNotification(`恭喜！${gameState.petName}升级到 ${gameState.level} 级！🎉`, "levelup");\n            gameState.health = Math.min(100, gameState.health + 10);\n            gameState.energy = Math.min(100, gameState.energy + 10);\n            updateDisplay();\n        }\n        \n        // 点击宠物\n        pet.addEventListener('click', () => {\n            if (!gameState.isSleeping) {\n                pet.classList.add('pet-happy');\n                gameState.happiness = Math.min(100, gameState.happiness + 5);\n                updateDisplay();\n                showMessage(`${gameState.petName}喜欢你！😊`);\n                \n                setTimeout(() => {\n                    pet.classList.remove('pet-happy');\n                }, 500);\n            }\n        });\n        \n        // 喂食按钮\n        feedBtn.addEventListener('click', () => {\n            if (Date.now() - gameState.lastFed < 5000) {\n                showMessage(`${gameState.petName}已经吃饱了，稍后再喂吧！⏱️`);\n                return;\n            }\n            \n            if (gameState.isSleeping) {\n                showMessage(`${gameState.petName}在睡觉，醒后再喂食吧！😴`);\n                return;\n            }\n            \n            if (gameState.health < 20) {\n                showMessage(`${gameState.petName}生病太严重了，先吃药吧！💊`);\n                return;\n            }\n            \n            gameState.lastFed = Date.now();\n            createFood();\n            feedBtn.disabled = true;\n            \n            // 添加冷却时间指示器\n            const cooldown = document.createElement('div');\n            cooldown.className = 'cooldown';\n            cooldown.textContent = '5';\n            feedBtn.appendChild(cooldown);\n            \n            let timeLeft = 5;\n            const cooldownInterval = setInterval(() => {\n                timeLeft--;\n                cooldown.textContent = timeLeft;\n                \n                if (timeLeft <= 0) {\n                    clearInterval(cooldownInterval);\n                    feedBtn.removeChild(cooldown);\n                    feedBtn.disabled = false;\n                }\n            }, 1000);\n        });\n        \n        // 玩耍按钮\n        playBtn.addEventListener('click', () => {\n            if (Date.now() - gameState.lastPlayed < 5000) {\n                showMessage(`${gameState.petName}已经玩累了，稍后再陪它玩吧！⏱️`);\n                return;\n            }\n            \n            if (gameState.isSleeping) {\n                showMessage(`${gameState.petName}在睡觉，醒后再陪它玩吧！😴`);\n                return;\n            }\n            \n            if (gameState.energy < 20) {\n                showMessage(`${gameState.petName}太累了，先让它休息一下吧！😴`);\n                return;\n            }\n            \n            if (gameState.health < 30) {\n                showMessage(`${gameState.petName}生病了，先吃药吧！💊`);\n                return;\n            }\n            \n            gameState.lastPlayed = Date.now();\n            createToy();\n            playBtn.disabled = true;\n            \n            // 添加冷却时间指示器\n            const cooldown = document.createElement('div');\n            cooldown.className = 'cooldown';\n            cooldown.textContent = '5';\n            playBtn.appendChild(cooldown);\n            \n            let timeLeft = 5;\n            const cooldownInterval = setInterval(() => {\n                timeLeft--;\n                cooldown.textContent = timeLeft;\n                \n                if (timeLeft <= 0) {\n                    clearInterval(cooldownInterval);\n                    playBtn.removeChild(cooldown);\n                    playBtn.disabled = false;\n                }\n            }, 1000);\n        });\n        \n        // 睡觉按钮\n        sleepBtn.addEventListener('click', () => {\n            if (gameState.isSleeping) {\n                // 醒来\n                gameState.isSleeping = false;\n                gameState.energy = 100;\n                gameState.sicknessLevel = Math.max(0, gameState.sicknessLevel - 10);\n                showMessage(`${gameState.petName}睡饱了，精神满满！⚡`);\n                sleepBtn.innerHTML = '<span>😴</span> 睡觉';\n                pet.classList.remove('pet-sleeping');\n                shower.style.display = 'none';\n            } else {\n                // 睡觉\n                if (gameState.energy > 80) {\n                    showMessage(`${gameState.petName}现在不困，先陪它玩一会儿吧！🎾`);\n                    return;\n                }\n                \n                gameState.isSleeping = true;\n                showMessage(`晚安！${gameState.petName}要睡觉了... 😴`);\n                sleepBtn.innerHTML = '<span>⏰</span> 醒来';\n                createShower();\n                \n                setTimeout(() => {\n                    shower.style.display = 'none';\n                }, 3000);\n            }\n            \n            updateDisplay();\n        });\n        \n        // 清洁按钮\n        cleanBtn.addEventListener('click', () => {\n            if (Date.now() - gameState.lastCleaned < 10000) {\n                showMessage(`${gameState.petName}还很干净，稍后再清洁吧！⏱️`);\n                return;\n            }\n            \n            if (gameState.isSleeping) {\n                showMessage(`${gameState.petName}在睡觉，醒后再清洁吧！😴`);\n                return;\n            }\n            \n            gameState.lastCleaned = Date.now();\n            gameState.happiness = Math.min(100, gameState.happiness + 10);\n            gameState.health = Math.min(100, gameState.health + 5);\n            gameState.sicknessLevel = Math.max(0, gameState.sicknessLevel - 15);\n            updateDisplay();\n            showMessage(`${gameState.petName}真干净！感觉舒服多了！😌`);\n        });\n        \n        // 医药按钮\n        medicineBtn.addEventListener('click', () => {\n            if (Date.now() - gameState.lastMedicine < 15000) {\n                showMessage(`${gameState.petName}最近吃过药了，稍后再用！⏱️`);\n                return;\n            }\n            \n            if (gameState.health >= 80) {\n                showMessage(`${gameState.petName}很健康，不需要吃药！💊`);\n                return;\n            }\n            \n            if (gameState.isSleeping) {\n                showMessage(`${gameState.petName}在睡觉，醒后再吃药吧！😴`);\n                return;\n            }\n            \n            gameState.lastMedicine = Date.now();\n            createMedicine();\n            medicineBtn.disabled = true;\n            \n            // 添加冷却时间指示器\n            const cooldown = document.createElement('div');\n            cooldown.className = 'cooldown';\n            cooldown.textContent = '15';\n            medicineBtn.appendChild(cooldown);\n            \n            let timeLeft = 15;\n            const cooldownInterval = setInterval(() => {\n                timeLeft--;\n                cooldown.textContent = timeLeft;\n                \n                if (timeLeft <= 0) {\n                    clearInterval(cooldownInterval);\n                    medicineBtn.removeChild(cooldown);\n                    medicineBtn.disabled = false;\n                }\n            }, 1000);\n        });\n        \n        // 维生素按钮\n        vitaminBtn.addEventListener('click', () => {\n            if (Date.now() - gameState.lastVitamin < 10000) {\n                showMessage(`${gameState.petName}最近补充过维生素了，稍后再用！⏱️`);\n                return;\n            }\n            \n            if (gameState.isSleeping) {\n                showMessage(`${gameState.petName}在睡觉，醒后再补充维生素吧！😴`);\n                return;\n            }\n            \n            gameState.lastVitamin = Date.now();\n            createVitamin();\n            vitaminBtn.disabled = true;\n            \n            // 添加冷却时间指示器\n            const cooldown = document.createElement('div');\n            cooldown.className = 'cooldown';\n            cooldown.textContent = '10';\n            vitaminBtn.appendChild(cooldown);\n            \n            let timeLeft = 10;\n            const cooldownInterval = setInterval(() => {\n                timeLeft--;\n                cooldown.textContent = timeLeft;\n                \n                if (timeLeft <= 0) {\n                    clearInterval(cooldownInterval);\n                    vitaminBtn.removeChild(cooldown);\n                    vitaminBtn.disabled = false;\n                }\n            }, 1000);\n        });\n        \n        // 状态随时间变化\n        setInterval(() => {\n            // 饱食度随时间降低\n            gameState.hunger = Math.max(0, gameState.hunger - 0.5);\n            \n            // 快乐度随时间降低\n            gameState.happiness = Math.max(0, gameState.happiness - 0.3);\n            \n            // 能量随时间恢复（睡觉时恢复更快）\n            if (gameState.isSleeping) {\n                gameState.energy = Math.min(100, gameState.energy + 2);\n            } else {\n                gameState.energy = Math.min(100, gameState.energy + 0.2);\n            }\n            \n            // 健康度受其他状态影响\n            if (gameState.hunger < 30 || gameState.happiness < 30) {\n                gameState.health = Math.max(0, gameState.health - 0.4);\n            }\n            \n            // 疾病等级自然恢复\n            if (gameState.sicknessLevel > 0) {\n                gameState.sicknessLevel = Math.max(0, gameState.sicknessLevel - 0.1);\n            }\n            \n            // 天气影响\n            const weatherEffect = weatherEffects[gameState.weather];\n            if (weatherEffect) {\n                gameState.health = Math.max(0, gameState.health + weatherEffect.health);\n                gameState.energy = Math.max(0, gameState.energy + weatherEffect.energy);\n            }\n            \n            // 极端天气额外影响\n            if (gameState.isHot && !gameState.isSleeping) {\n                gameState.energy = Math.max(0, gameState.energy - 0.3);\n            }\n            \n            if (gameState.isCold && !gameState.isSleeping) {\n                gameState.energy = Math.max(0, gameState.energy - 0.2);\n                gameState.happiness = Math.max(0, gameState.happiness - 0.2);\n            }\n            \n            // 如果健康度很低，宠物会睡觉恢复\n            if (gameState.health < 20 && !gameState.isSleeping) {\n                showEventNotification(`${gameState.petName}太虚弱了，需要休息！😴`, "tired");\n                gameState.isSleeping = true;\n                sleepBtn.click();\n            }\n            \n            // 随机事件系统\n            if (Math.random() < 0.005) { // 0.5%的概率触发随机事件\n                triggerRandomEvent();\n            }\n            \n            updateDisplay();\n            \n            // 检查游戏结束条件\n            if (gameState.hunger === 0 && gameState.happiness === 0 && gameState.energy === 0 && gameState.health === 0) {\n                showMessage(`${gameState.petName}离开了...请重新加载页面开始新的旅程。😢`);\n                pet.style.opacity = '0.3';\n            }\n        }, 2000);\n        \n        // 随机事件系统\n        function triggerRandomEvent() {\n            const events = [\n                {\n                    name: "发现了美食",\n                    effect: () => {\n                        gameState.hunger = Math.min(100, gameState.hunger + 20);\n                        showEventNotification(`${gameState.petName}发现了美食！`, "good");\n                    }\n                },\n                {\n                    name: "遇到了朋友",\n                    effect: () => {\n                        gameState.happiness = Math.min(100, gameState.happiness + 15);\n                        showEventNotification(`${gameState.petName}遇到了好朋友！`, "good");\n                    }\n                },\n                {\n                    name: "天气突变",\n                    effect: () => {\n                        const weathers = ['hot', 'cold'];\n                        const randomWeather = weathers[Math.floor(Math.random() * weathers.length)];\n                        changeWeather(randomWeather);\n                        showEventNotification(`天气突然${randomWeather === 'hot' ? '变热' : '变冷'}了！`, "warning");\n                    }\n                }\n            ];\n            \n            const event = events[Math.floor(Math.random() * events.length)];\n            event.effect();\n        }\n        \n        // 初始化显示\n        updateDisplay();\n        updateTemperatureDisplay();\n        \n        // 防止页面滚动\n        document.addEventListener('touchmove', (e) => {\n            if (e.target.closest('.game-container')) {\n                e.preventDefault();\n            }\n        }, { passive: false });\n        \n        // 添加键盘支持\n        document.addEventListener('keydown', (e) => {\n            switch(e.key.toLowerCase()) {\n                case 'f':\n                    feedBtn.click();\n                    break;\n                case 'p':\n                    playBtn.click();\n                    break;\n                case 's':\n                    sleepBtn.click();\n                    break;\n                case 'c':\n                    cleanBtn.click();\n                    break;\n                case 'm':\n                    medicineBtn.click();\n                    break;\n                case 'v':\n                    vitaminBtn.click();\n                    break;\n            }\n        });\n    });\n    </script>\n</body>\n</html>			\N	\N	\N	2025-11-25 14:01:23.521	2025-11-27 13:04:43.897	模拟养动物	t
35de6ab8-5d4d-4ed7-bbeb-f122bb1a5691	b43124b2-f848-4f92-8b18-a36fc7ab57af	兵团	\N	<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>兵团 - 策略指挥游戏</title>\n    <style>\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        \n        body {\n            font-family: 'Arial', sans-serif;\n            background: linear-gradient(135deg, #f6f9fc 0%, #e9f2ff 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow-x: hidden;\n            overflow-y: auto;\n            padding: 10px;\n        }\n        \n        .game-container {\n            width: 95%;\n            max-width: 1200px;\n            background-color: white;\n            border-radius: 20px;\n            box-shadow: 0 15px 30px rgba(0, 0, 0, 0.1);\n            overflow: hidden;\n            margin: 10px auto;\n        }\n        \n        .game-header {\n            background: linear-gradient(90deg, #4facfe 0%, #00f2fe 100%);\n            color: white;\n            padding: 20px;\n            text-align: center;\n        }\n        \n        .game-header h1 {\n            font-size: 2.5rem;\n            margin-bottom: 10px;\n            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);\n        }\n        \n        .game-info {\n            display: flex;\n            justify-content: space-around;\n            margin-top: 15px;\n            flex-wrap: wrap;\n        }\n        \n        .info-item {\n            background-color: rgba(255, 255, 255, 0.2);\n            padding: 10px 20px;\n            border-radius: 10px;\n            font-weight: bold;\n            margin: 5px;\n        }\n        \n        .game-area {\n            display: flex;\n            flex-direction: column;\n            height: auto;\n            padding: 20px;\n        }\n        \n        .battlefield-container {\n            width: 100%;\n            margin-bottom: 20px;\n            position: relative;\n        }\n        \n        .battlefield {\n            width: 100%;\n            aspect-ratio: 1;\n            max-width: 600px;\n            margin: 0 auto;\n            display: grid;\n            grid-template-columns: repeat(10, 1fr);\n            grid-template-rows: repeat(10, 1fr);\n            gap: 5px;\n            background-color: #f0f7ff;\n            padding: 5px;\n            border-radius: 10px;\n        }\n        \n        .cell {\n            background-color: white;\n            border-radius: 8px;\n            box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            font-size: 1.5rem;\n            transition: all 0.2s ease;\n            cursor: pointer;\n            position: relative;\n        }\n        \n        .cell:hover {\n            transform: scale(1.05);\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.1);\n        }\n        \n        .cell.possible-move {\n            background-color: #ccffcc;\n            border: 2px dashed #4caf50;\n        }\n        \n        .cell.selected {\n            border: 3px solid #4facfe;\n        }\n        \n        .cell.base-target {\n            border: 3px solid #ff5722;\n            animation: base-glow 1.5s infinite;\n        }\n        \n        .cell.defensive-zone {\n            background-color: #ffe0b2;\n            animation: pulse 3s infinite;\n        }\n        \n        @keyframes base-glow {\n            0% { box-shadow: 0 0 5px #ff5722; }\n            50% { box-shadow: 0 0 15px #ff5722, 0 0 20px #ff5722; }\n            100% { box-shadow: 0 0 5px #ff5722; }\n        }\n        \n        @keyframes pulse {\n            0% { opacity: 0.7; }\n            50% { opacity: 1; }\n            100% { opacity: 0.7; }\n        }\n        \n        .player-soldier {\n            color: #4facfe;\n            animation: pulse 1.5s infinite;\n        }\n        \n        .player-soldier.moved {\n            opacity: 0.7;\n            animation: none;\n        }\n        \n        .player-knight {\n            color: #2196F3;\n            animation: pulse 2s infinite;\n            font-size: 1.8rem;\n        }\n        \n        .player-knight.moved {\n            opacity: 0.7;\n            animation: none;\n        }\n        \n        .enemy-soldier {\n            color: #f44336;\n        }\n        \n        .enemy-knight {\n            color: #d32f2f;\n            font-size: 1.8rem;\n        }\n        \n        .enemy-base {\n            color: #b71c1c;\n            font-size: 1.7rem;\n        }\n        \n        .enemy-target {\n            color: #ff5722;\n            font-size: 1.9rem;\n            animation: base-pulse 2s infinite;\n        }\n        \n        @keyframes base-pulse {\n            0% { transform: scale(1); }\n            50% { transform: scale(1.2); }\n            100% { transform: scale(1); }\n        }\n        \n        @keyframes pulse {\n            0% { transform: scale(1); }\n            50% { transform: scale(1.1); }\n            100% { transform: scale(1); }\n        }\n        \n        @keyframes recruit-animation {\n            0% { transform: scale(0.5); opacity: 0.5; }\n            50% { transform: scale(1.2); }\n            100% { transform: scale(1); opacity: 1; }\n        }\n        \n        .recruiting {\n            animation: recruit-animation 0.5s ease;\n        }\n        \n        .controls {\n            width: 100%;\n            background-color: #f8f9fa;\n            padding: 20px;\n            border-radius: 15px;\n            margin-top: 20px;\n        }\n        \n        .control-section {\n            margin-bottom: 25px;\n        }\n        \n        .control-section h3 {\n            margin-bottom: 15px;\n            color: #495057;\n            font-size: 1.2rem;\n        }\n        \n        .recruit-menu {\n            display: none;\n            position: fixed;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            background-color: white;\n            padding: 20px;\n            border-radius: 15px;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);\n            z-index: 1001;\n            width: 300px;\n            max-width: 90vw;\n        }\n        \n        .recruit-menu.active {\n            display: block;\n        }\n        \n        .recruit-option {\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            padding: 15px;\n            margin-bottom: 10px;\n            background-color: #f1f1f1;\n            border-radius: 8px;\n            cursor: pointer;\n            transition: all 0.2s ease;\n        }\n        \n        .recruit-option:hover {\n            background-color: #e9ecef;\n            transform: translateY(-2px);\n        }\n        \n        .recruit-info {\n            display: flex;\n            align-items: center;\n        }\n        \n        .recruit-symbol {\n            font-size: 2rem;\n            margin-right: 15px;\n        }\n        \n        .recruit-stats {\n            font-size: 0.9rem;\n            color: #666;\n        }\n        \n        .control-btn {\n            width: 100%;\n            padding: 12px;\n            margin-bottom: 10px;\n            border: none;\n            border-radius: 8px;\n            font-size: 1rem;\n            font-weight: bold;\n            cursor: pointer;\n            transition: all 0.2s ease;\n        }\n        \n        .move-btn {\n            background-color: #4facfe;\n            color: white;\n        }\n        \n        .move-btn:hover {\n            background-color: #3a8bfe;\n            transform: translateY(-2px);\n        }\n        \n        .action-btn {\n            background-color: #ff5722;\n            color: white;\n        }\n        \n        .action-btn:hover {\n            background-color: #e64a19;\n            transform: translateY(-2px);\n        }\n        \n        .turn-btn {\n            background-color: #9c27b0;\n            color: white;\n        }\n        \n        .turn-btn:hover {\n            background-color: #7b1fa2;\n            transform: translateY(-2px);\n        }\n        \n        .legend {\n            margin-top: 15px;\n            padding: 10px;\n            background-color: #f1f1f1;\n            border-radius: 8px;\n        }\n        \n        .legend-item {\n            display: flex;\n            align-items: center;\n            margin-bottom: 5px;\n        }\n        \n        .legend-symbol {\n            width: 25px;\n            margin-right: 10px;\n        }\n        \n        .instructions {\n            margin-top: 15px;\n            padding: 15px;\n            background-color: #e9f7ff;\n            border-radius: 8px;\n            font-size: 0.9rem;\n        }\n        \n        .overlay {\n            position: fixed;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            background-color: rgba(0, 0, 0, 0.5);\n            z-index: 1000;\n            display: none;\n        }\n        \n        .overlay.active {\n            display: block;\n        }\n        \n        .resources {\n            display: flex;\n            justify-content: space-around;\n            margin-top: 15px;\n            flex-wrap: wrap;\n        }\n        \n        .resource-item {\n            background-color: rgba(255, 255, 255, 0.2);\n            padding: 8px 15px;\n            border-radius: 8px;\n            margin: 3px;\n            font-size: 0.9rem;\n        }\n        \n        .enemy-resources {\n            display: flex;\n            justify-content: space-around;\n            margin-top: 10px;\n            font-size: 0.8rem;\n        }\n        \n        .mission-panel {\n            background-color: #fff3e0;\n            padding: 15px;\n            border-radius: 10px;\n            margin-bottom: 20px;\n            border: 2px solid #ff9800;\n        }\n        \n        .mission-title {\n            font-weight: bold;\n            color: #e65100;\n            margin-bottom: 10px;\n            font-size: 1.1rem;\n            text-align: center;\n        }\n        \n        .mission-description {\n            font-size: 0.9rem;\n            color: #bf360c;\n        }\n        \n        .unit-health {\n            position: absolute;\n            bottom: -5px;\n            right: -5px;\n            font-size: 0.7rem;\n            background-color: rgba(0, 0, 0, 0.7);\n            color: white;\n            padding: 2px 5px;\n            border-radius: 10px;\n        }\n        \n        .key-hint {\n            display: inline-block;\n            background-color: #333;\n            color: white;\n            padding: 2px 6px;\n            border-radius: 4px;\n            font-size: 0.75rem;\n            margin-left: 5px;\n        }\n        \n        .message {\n            position: fixed;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            background-color: white;\n            padding: 30px;\n            border-radius: 15px;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);\n            z-index: 1002;\n            width: 350px;\n            text-align: center;\n            display: none;\n            max-width: 90vw;\n        }\n        \n        .message.active {\n            display: block;\n        }\n        \n        /* 响应式设计 */\n        @media (min-width: 768px) {\n            .game-area {\n                flex-direction: row;\n            }\n            \n            .battlefield-container {\n                flex: 1;\n                margin-bottom: 0;\n                margin-right: 20px;\n            }\n            \n            .controls {\n                width: 300px;\n                margin-top: 0;\n            }\n        }\n        \n        @media (max-width: 767px) {\n            .game-container {\n                width: 100%;\n                margin: 5px;\n            }\n            \n            .game-header h1 {\n                font-size: 2rem;\n            }\n            \n            .info-item {\n                font-size: 0.9rem;\n                padding: 8px 12px;\n            }\n        }\n        \n        /* 滚动条样式 */\n        ::-webkit-scrollbar {\n            width: 10px;\n            height: 10px;\n        }\n        \n        ::-webkit-scrollbar-track {\n            background: #f1f1f1;\n            border-radius: 5px;\n        }\n        \n        ::-webkit-scrollbar-thumb {\n            background: #4facfe;\n            border-radius: 5px;\n        }\n        \n        ::-webkit-scrollbar-thumb:hover {\n            background: #3a8bfe;\n        }\n    </style>\n</head>\n<body>\n    <div class="game-container">\n        <div class="game-header">\n            <h1>兵团</h1>\n            <div class="game-info">\n                <div class="info-item">\n                    <span>回合: </span><span id="round">1</span>\n                </div>\n                <div class="info-item">\n                    <span>分数: </span><span id="score">0</span>\n                </div>\n                <div class="info-item">\n                    <span>任芊浔军队总兵力: </span><span id="playerUnits">5</span>\n                </div>\n                <div class="info-item">\n                    <span>敌军总兵力: </span><span id="enemyUnits">6</span>\n                </div>\n            </div>\n            \n            <div class="resources">\n                <div class="resource-item">\n                    <span>任芊浔国家金币: </span><span id="gold">100</span>\n                </div>\n                <div class="resource-item">\n                    <span>任芊浔招募点数: </span><span id="recruitmentPoints">3</span>\n                </div>\n            </div>\n            \n            <div class="enemy-resources">\n                <div class="resource-item">\n                    <span>敌军金币: </span><span id="enemyGold">80</span>\n                </div>\n                <div class="resource-item">\n                    <span>敌军招募点数: </span><span id="enemyRecruitmentPoints">2</span>\n                </div>\n            </div>\n        </div>\n        \n        <div class="game-area">\n            <div class="battlefield-container">\n                <div class="battlefield" id="battlefield"></div>\n            </div>\n            \n            <div class="controls">\n                <div class="mission-panel">\n                    <div class="mission-title">⚔️ 任务目标</div>\n                    <div class="mission-description">\n                        占领敌军指挥部获得胜利！\n                        <br>击败所有敌方单位也能获胜。\n                    </div>\n                </div>\n                \n                <div class="control-section">\n                    <h3>兵团行动</h3>\n                    <button class="control-btn move-btn" id="recruitBtn">招募单位 <span class="key-hint">R</span></button>\n                    <button class="control-btn move-btn" id="moveBtn">移动单位 <span class="key-hint">M</span></button>\n                    <button class="control-btn action-btn" id="attackBtn">发动攻击 <span class="key-hint">A</span></button>\n                    <button class="control-btn move-btn" id="defendBtn">防御姿态 <span class="key-hint">D</span></button>\n                </div>\n                \n                <div class="control-section">\n                    <h3>回合控制</h3>\n                    <button class="control-btn turn-btn" id="endTurnBtn">结束回合 <span class="key-hint">E</span></button>\n                    <div style="text-align: center; margin-top: 15px; font-size: 0.85rem; color: #666;">\n                        快捷键：<br>\n                        下一回合 <span class="key-hint">↓/S</span><br>\n                        撤销选择 <span class="key-hint">Space</span><br>\n                        取消操作 <span class="key-hint">Esc</span>\n                    </div>\n                </div>\n                \n                <div class="control-section">\n                    <h3>游戏状态</h3>\n                    <div id="statusText" style="text-align: center; margin-bottom: 15px;">准备战斗</div>\n                </div>\n                \n                <div class="legend">\n                    <h3>单位图例</h3>\n                    <div class="legend-item">\n                        <span class="legend-symbol">⚔️</span>\n                        <span>我军士兵</span>\n                    </div>\n                    <div class="legend-item">\n                        <span class="legend-symbol">🐎</span>\n                        <span>我军骑士</span>\n                    </div>\n                    <div class="legend-item">\n                        <span class="legend-symbol">🔴</span>\n                        <span>敌军士兵</span>\n                    </div>\n                    <div class="legend-item">\n                        <span class="legend-symbol">🐺</span>\n                        <span>敌军骑士</span>\n                    </div>\n                    <div class="legend-item">\n                        <span class="legend-symbol">🏴</span>\n                        <span>敌军指挥部</span>\n                    </div>\n                </div>\n                \n                <div class="instructions">\n                    <h3>操作说明</h3>\n                    <p>• 选择你的单位后可看到绿色移动范围</p>\n                    <p>• 敌军少于5个时会优先招募单位</p>\n                    <p>• 敌军足够(8个)时会主动进攻</p>\n                    <p>• ↓键快速进入下一回合</p>\n                    <p>• 方向键或WASD移动选中的单位</p>\n                </div>\n            </div>\n        </div>\n    </div>\n    \n    <div class="overlay" id="overlay"></div>\n    \n    <div class="recruit-menu" id="recruitMenu">\n        <h3 style="margin-bottom: 15px;">招募单位</h3>\n        <div class="recruit-option" id="recruitSoldier">\n            <div class="recruit-info">\n                <div class="recruit-symbol">⚔️</div>\n                <div>\n                    <div style="font-weight: bold;">招募士兵</div>\n                    <div class="recruit-stats">金币: 30 | 攻击:1 | 生命:3</div>\n                </div>\n            </div>\n        </div>\n        <div class="recruit-option" id="recruitKnight">\n            <div class="recruit-info">\n                <div class="recruit-symbol">🐎</div>\n                <div>\n                    <div style="font-weight: bold;">招募骑士</div>\n                    <div class="recruit-stats">金币: 60 | 攻击:2 | 生命:5</div>\n                </div>\n            </div>\n        </div>\n        <button class="control-btn" id="cancelRecruitBtn" style="background-color: #f44336; color: white; margin-top: 15px;">取消</button>\n    </div>\n    \n    <script>\n        // 游戏状态\n        const gameState = {\n            round: 1,\n            score: 0,\n            playerUnits: 0,\n            enemyUnits: 0,\n            gold: 100,\n            enemyGold: 80,\n            recruitmentPoints: 3,\n            enemyRecruitmentPoints: 2,\n            selectedUnit: null,\n            mode: 'normal', // normal, recruit, move, attack, defend\n            playerTurn: true,\n            gameOver: false,\n            aiDifficulty: 'medium', // 敌军AI难度\n            enemyMinUnits: 5,\n            enemyMaxUnits: 8\n        };\n        \n        // 战场数据\n        const battlefieldSize = 10;\n        const battlefield = [];\n        \n        // 单位类型\n        const unitTypes = {\n            // 我军单位\n            playerSoldier: { \n                symbol: '⚔️', \n                class: 'player-soldier', \n                power: 1, \n                health: 3,\n                maxHealth: 3,\n                movement: 1,\n                moved: false,\n                name: '士兵',\n                cost: 30\n            },\n            playerKnight: { \n                symbol: '🐎', \n                class: 'player-knight', \n                power: 2, \n                health: 5,\n                maxHealth: 5,\n                movement: 2,\n                moved: false,\n                name: '骑士',\n                cost: 60\n            },\n            \n            // 敌军单位\n            enemySoldier: { \n                symbol: '🔴', \n                class: 'enemy-soldier', \n                power: 1, \n                health: 3,\n                maxHealth: 3,\n                movement: 1,\n                name: '敌兵',\n                cost: 25\n            },\n            enemyKnight: { \n                symbol: '🐺', \n                class: 'enemy-knight', \n                power: 2, \n                health: 5,\n                maxHealth: 5,\n                movement: 2,\n                name: '敌骑',\n                cost: 50\n            },\n            enemyBase: { \n                symbol: '🏴', \n                class: 'enemy-base', \n                power: 0, \n                health: 1,\n                maxHealth: 1,\n                movement: 0,\n                name: '指挥部'\n            }\n        };\n        \n        // 敌军AI策略\n        const aiStrategies = {\n            // 保守策略：主要防守，以保护指挥部为主\n            defensive: {\n                soldierToKnightRatio: 4,\n                baseDefensePriority: 1,\n                recruitThreshold: 0.8\n            },\n            // 平衡策略：攻守兼备\n            balanced: {\n                soldierToKnightRatio: 2,\n                baseDefensePriority: 0.7,\n                recruitThreshold: 0.6\n            },\n            // 激进策略：主动进攻\n            aggressive: {\n                soldierToKnightRatio: 1,\n                baseDefensePriority: 0.3,\n                recruitThreshold: 0.4\n            }\n        };\n        \n        // 初始化战场\n        function initBattlefield() {\n            const battlefieldElement = document.getElementById('battlefield');\n            battlefieldElement.innerHTML = '';\n            \n            // 初始化网格数据\n            for (let i = 0; i < battlefieldSize; i++) {\n                battlefield[i] = [];\n                for (let j = 0; j < battlefieldSize; j++) {\n                    battlefield[i][j] = null;\n                    \n                    // 创建单元格\n                    const cell = document.createElement('div');\n                    cell.className = 'cell';\n                    cell.dataset.row = i;\n                    cell.dataset.col = j;\n                    \n                    // 添加事件监听\n                    cell.addEventListener('click', handleCellClick);\n                    \n                    battlefieldElement.appendChild(cell);\n                }\n            }\n            \n            // 放置初始单位\n            placeUnit(1, 4, 'playerSoldier');\n            placeUnit(2, 3, 'playerSoldier');\n            placeUnit(2, 5, 'playerSoldier');\n            placeUnit(3, 4, 'playerSoldier');\n            placeUnit(3, 5, 'playerKnight');\n            \n            // 放置敌军单位\n            placeUnit(6, 4, 'enemySoldier');\n            placeUnit(7, 3, 'enemyKnight');\n            placeUnit(7, 5, 'enemySoldier');\n            placeUnit(8, 4, 'enemySoldier');\n            placeUnit(8, 5, 'enemySoldier');\n            placeUnit(9, 4, 'enemyBase'); // 敌军指挥部\n            placeUnit(9, 5, 'enemySoldier'); // 额外的敌军士兵\n            \n            highlightCommandCenter();\n            markDefensiveZone();\n        }\n        \n        // 标记防御区域\n        function markDefensiveZone() {\n            // 标记指挥部周围的防御区域\n            const directions = [\n                { row: -1, col: 0 },\n                { row: -2, col: 0 },\n                { row: 0, col: -1 },\n                { row: 0, col: -2 },\n                { row: -1, col: -1 },\n                { row: -1, col: 1 },\n                { row: -2, col: -1 },\n                { row: -2, col: 1 }\n            ];\n            \n            // 找到所有敌军指挥部\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyBase') {\n                        // 标记周围的区域为防御区\n                        directions.forEach(dir => {\n                            const row = i + dir.row;\n                            const col = j + dir.col;\n                            \n                            if (row >= 0 && row < battlefieldSize && \n                                col >= 0 && col < battlefieldSize &&\n                                battlefield[row][col] === null) {\n                                const cell = document.querySelector(`[data-row="${row}"][data-col="${col}"]`);\n                                cell.classList.add('defensive-zone');\n                            }\n                        });\n                    }\n                }\n            }\n        }\n        \n        // 高亮显示敌军指挥部\n        function highlightCommandCenter() {\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyBase') {\n                        const cell = document.querySelector(`[data-row="${i}"][data-col="${j}"]`);\n                        cell.classList.add('enemy-target');\n                    }\n                }\n            }\n        }\n        \n        // 在指定位置放置单位\n        function placeUnit(row, col, type) {\n            const unitData = { ...unitTypes[type] };\n            if (type === 'playerSoldier' || type === 'playerKnight') {\n                unitData.moved = false;\n            }\n            unitData.type = type;\n            unitData.row = row;\n            unitData.col = col;\n            \n            battlefield[row][col] = unitData;\n            updateCell(row, col);\n            \n            // 更新单位计数\n            if (type === 'playerSoldier' || type === 'playerKnight') {\n                gameState.playerUnits++;\n                updateUnits();\n            } else if (type.startsWith('enemy')) {\n                gameState.enemyUnits++;\n                updateUnits();\n            }\n        }\n        \n        // 更新单元格显示\n        function updateCell(row, col) {\n            const cell = document.querySelector(`[data-row="${row}"][data-col="${col}"]`);\n            const unit = battlefield[row][col];\n            \n            // 清除单元格内容\n            cell.innerHTML = '';\n            \n            if (unit) {\n                // 创建单位符号\n                const unitSymbol = document.createElement('span');\n                unitSymbol.textContent = unit.symbol;\n                cell.appendChild(unitSymbol);\n                \n                // 添加生命值显示\n                if (unit.health < unit.maxHealth) {\n                    const healthBar = document.createElement('div');\n                    healthBar.className = 'unit-health';\n                    healthBar.textContent = `${unit.health}/${unit.maxHealth}`;\n                    cell.appendChild(healthBar);\n                }\n                \n                // 应用样式\n                cell.className = 'cell';\n                \n                if (unit.type === 'playerSoldier') {\n                    cell.classList.add('player-soldier');\n                    if (unit.moved) {\n                        cell.classList.add('moved');\n                    }\n                } else if (unit.type === 'playerKnight') {\n                    cell.classList.add('player-knight');\n                    if (unit.moved) {\n                        cell.classList.add('moved');\n                    }\n                } else if (unit.type === 'enemySoldier') {\n                    cell.classList.add('enemy-soldier');\n                } else if (unit.type === 'enemyKnight') {\n                    cell.classList.add('enemy-knight');\n                } else if (unit.type === 'enemyBase') {\n                    cell.classList.add('enemy-base');\n                    cell.classList.add('enemy-target');\n                }\n                \n                if (unit === gameState.selectedUnit) {\n                    cell.classList.add('selected');\n                }\n            } else {\n                cell.textContent = '';\n                cell.className = 'cell';\n            }\n        }\n        \n        // 处理单元格点击\n        function handleCellClick(e) {\n            if (!gameState.playerTurn || gameState.gameOver) return;\n            \n            const row = parseInt(e.target.dataset.row);\n            const col = parseInt(e.target.dataset.col);\n            const unit = battlefield[row][col];\n            \n            if (gameState.mode === 'normal') {\n                if (unit && (unit.type === 'playerSoldier' || unit.type === 'playerKnight') && !unit.moved) {\n                    selectUnit(unit);\n                } else if (gameState.selectedUnit && !unit) {\n                    moveUnit(row, col);\n                } else if (gameState.selectedUnit && unit) {\n                    if (unit.type === 'enemySoldier' || unit.type === 'enemyKnight' || unit.type === 'enemyBase') {\n                        if (canAttack(gameState.selectedUnit, row, col)) {\n                            performAttack(gameState.selectedUnit, row, col);\n                        }\n                    }\n                }\n            } else if (gameState.mode === 'move') {\n                if (gameState.selectedUnit && canMove(gameState.selectedUnit, row, col)) {\n                    moveUnit(row, col);\n                } else if (unit && (unit.type === 'playerSoldier' || unit.type === 'playerKnight') && !unit.moved) {\n                    selectUnit(unit);\n                }\n            } else if (gameState.mode === 'attack') {\n                if (gameState.selectedUnit && canAttack(gameState.selectedUnit, row, col)) {\n                    performAttack(gameState.selectedUnit, row, col);\n                } else if (unit && (unit.type === 'playerSoldier' || unit.type === 'playerKnight') && !unit.moved) {\n                    selectUnit(unit);\n                }\n            }\n        }\n        \n        // 选择单位\n        function selectUnit(unit) {\n            // 清除之前的选择\n            if (gameState.selectedUnit) {\n                updateCell(gameState.selectedUnit.row, gameState.selectedUnit.col);\n            }\n            \n            gameState.selectedUnit = unit;\n            updateCell(unit.row, unit.col);\n            \n            if (gameState.mode === 'normal') {\n                showPossibleMoves(unit);\n                \n                // 如果附近有敌军指挥部，特别提示\n                const nearbyBase = findNearbyCommandCenter(unit.row, unit.col);\n                if (nearbyBase) {\n                    updateStatus(`🎯 机会！${unit.name}可以攻击敌军指挥部！`);\n                    const baseCell = document.querySelector(`[data-row="${nearbyBase.row}"][data-col="${nearbyBase.col}"]`);\n                    baseCell.classList.add('base-target');\n                } else {\n                    updateStatus(`已选择${unit.name} (${unit.row}, ${unit.col}) - 攻击力:${unit.power}, 生命:${unit.health}/${unit.maxHealth}`);\n                }\n            }\n        }\n        \n        // 查找附近的敌军指挥部\n        function findNearbyCommandCenter(row, col) {\n            const distances = [];\n            \n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyBase') {\n                        const distance = Math.abs(row - i) + Math.abs(col - j);\n                        distances.push({ row: i, col: j, distance: distance });\n                    }\n                }\n            }\n            \n            // 返回最近的指挥部\n            if (distances.length > 0) {\n                distances.sort((a, b) => a.distance - b.distance);\n                // 如果距离在攻击范围内（1格），返回该指挥部\n                if (distances[0].distance === 1) {\n                    return distances[0];\n                }\n            }\n            \n            return null;\n        }\n        \n        // 显示可能的移动位置\n        function showPossibleMoves(unit) {\n            // 清除之前的标记\n            document.querySelectorAll('.possible-move').forEach(cell => {\n                cell.classList.remove('possible-move');\n            });\n            document.querySelectorAll('.base-target').forEach(cell => {\n                cell.classList.remove('base-target');\n            });\n            \n            const directions = [\n                { row: -1, col: 0 },\n                { row: 1, col: 0 },\n                { row: 0, col: -1 },\n                { row: 0, col: 1 }\n            ];\n            \n            // 根据单位的移动范围计算可能的位置\n            for (let dist = 1; dist <= unit.movement; dist++) {\n                directions.forEach(dir => {\n                    const newRow = unit.row + dir.row * dist;\n                    const newCol = unit.col + dir.col * dist;\n                    \n                    if (canMove(unit, newRow, newCol)) {\n                        const cell = document.querySelector(`[data-row="${newRow}"][data-col="${newCol}"]`);\n                        cell.classList.add('possible-move');\n                    }\n                });\n            }\n        }\n        \n        // 移动单位\n        function moveUnit(targetRow, targetCol) {\n            if (!canMove(gameState.selectedUnit, targetRow, targetCol)) {\n                updateStatus('无法移动到该位置');\n                return;\n            }\n            \n            // 清除原位置\n            battlefield[gameState.selectedUnit.row][gameState.selectedUnit.col] = null;\n            updateCell(gameState.selectedUnit.row, gameState.selectedUnit.col);\n            \n            // 设置新位置\n            gameState.selectedUnit.row = targetRow;\n            gameState.selectedUnit.col = targetCol;\n            gameState.selectedUnit.moved = true;\n            battlefield[targetRow][targetCol] = gameState.selectedUnit;\n            \n            updateCell(targetRow, targetCol);\n            \n            // 清除所有可能的移动标记\n            document.querySelectorAll('.possible-move').forEach(cell => {\n                cell.classList.remove('possible-move');\n            });\n            document.querySelectorAll('.base-target').forEach(cell => {\n                cell.classList.remove('base-target');\n            });\n            \n            updateStatus(`${gameState.selectedUnit.name}移动成功`);\n        }\n        \n        // 检查是否可以移动\n        function canMove(unit, targetRow, targetCol) {\n            // 检查是否在战场范围内\n            if (targetRow < 0 || targetRow >= battlefieldSize || targetCol < 0 || targetCol >= battlefieldSize) {\n                return false;\n            }\n            \n            // 检查是否是有效距离\n            const rowDiff = Math.abs(unit.row - targetRow);\n            const colDiff = Math.abs(unit.col - targetCol);\n            const distance = rowDiff + colDiff;\n            \n            if (distance > unit.movement) {\n                return false;\n            }\n            \n            // 检查目标位置是否为空\n            return battlefield[targetRow][targetCol] === null;\n        }\n        \n        // 检查是否可以攻击\n        function canAttack(unit, targetRow, targetCol) {\n            const targetUnit = battlefield[targetRow][targetCol];\n            \n            if (!targetUnit) return false;\n            \n            // 只能攻击敌方单位\n            const enemyTypes = ['enemySoldier', 'enemyKnight', 'enemyBase'];\n            if (!enemyTypes.includes(targetUnit.type)) return false;\n            \n            // 检查是否在攻击范围内\n            const rowDiff = Math.abs(unit.row - targetRow);\n            const colDiff = Math.abs(unit.col - targetCol);\n            \n            return rowDiff <= 1 && colDiff <= 1;\n        }\n        \n        // 执行攻击\n        function performAttack(attacker, targetRow, targetCol) {\n            const defender = battlefield[targetRow][targetCol];\n            \n            // 计算伤害\n            let damage = attacker.power;\n            \n            // 检查防御状态\n            if (defender.defending) {\n                damage = Math.floor(damage / 2);\n            }\n            \n            defender.health -= damage;\n            updateCell(targetRow, targetCol);\n            \n            if (defender.health <= 0) {\n                // 敌方单位被消灭\n                battlefield[targetRow][targetCol] = null;\n                updateCell(targetRow, targetCol);\n                \n                let points = 10;\n                let goldReward = 5;\n                \n                if (defender.type === 'enemyBase') {\n                    // 击败指挥部获得大量奖励\n                    points = 100;\n                    goldReward = 50;\n                    updateStatus(`🎉 胜利！你的${attacker.name}成功摧毁了敌军指挥部！你赢得了战争！`);\n                } else {\n                    updateStatus(`${attacker.name}击败了${defender.name}！获得${points}分和${goldReward}金币`);\n                }\n                \n                gameState.score += points;\n                gameState.gold += goldReward;\n                updateScore();\n                updateGold();\n                \n                // 更新敌军数量\n                gameState.enemyUnits--;\n                updateUnits();\n                \n                // 如果是敌军指挥部被占领，游戏胜利\n                if (defender.type === 'enemyBase') {\n                    gameOver(true);\n                }\n            } else {\n                updateStatus(`${attacker.name}攻击${defender.name}，造成${damage}点伤害，剩余生命：${defender.health}/${defender.maxHealth}`);\n            }\n            \n            attacker.moved = true;\n            gameState.mode = 'normal';\n            \n            // 清除所有可能的移动标记\n            document.querySelectorAll('.possible-move').forEach(cell => {\n                cell.classList.remove('possible-move');\n            });\n            document.querySelectorAll('.base-target').forEach(cell => {\n                cell.classList.remove('base-target');\n            });\n            \n            // 检查游戏是否结束\n            checkGameOver();\n        }\n        \n        // 显示招募菜单\n        function showRecruitMenu() {\n            if (gameState.recruitmentPoints <= 0) {\n                updateStatus('没有可用的招募点数！');\n                return;\n            }\n            \n            document.getElementById('overlay').classList.add('active');\n            document.getElementById('recruitMenu').classList.add('active');\n            \n            updateStatus('选择要招募的单位');\n        }\n        \n        // 隐藏招募菜单\n        function hideRecruitMenu() {\n            document.getElementById('overlay').classList.remove('active');\n            document.getElementById('recruitMenu').classList.remove('active');\n        }\n        \n        // 招募士兵\n        function recruitSoldier() {\n            if (gameState.recruitmentPoints <= 0) {\n                updateStatus('没有可用的招募点数！');\n                return;\n            }\n            \n            if (gameState.gold < unitTypes.playerSoldier.cost) {\n                updateStatus('金币不足！需要30金币招募士兵');\n                return;\n            }\n            \n            // 找到合适的招募位置\n            const emptyCells = [];\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] === null && i < battlefieldSize / 2) {\n                        emptyCells.push({ row: i, col: j });\n                    }\n                }\n            }\n            \n            if (emptyCells.length > 0) {\n                const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];\n                placeUnit(randomCell.row, randomCell.col, 'playerSoldier');\n                \n                // 添加招募动画\n                const cell = document.querySelector(`[data-row="${randomCell.row}"][data-col="${randomCell.col}"]`);\n                cell.classList.add('recruiting');\n                setTimeout(() => {\n                    cell.classList.remove('recruiting');\n                }, 500);\n                \n                gameState.gold -= unitTypes.playerSoldier.cost;\n                gameState.recruitmentPoints--;\n                \n                updateGold();\n                updateRecruitmentPoints();\n                updateStatus('成功招募了新的士兵！');\n                \n                hideRecruitMenu();\n            } else {\n                updateStatus('没有可用的招募位置');\n            }\n        }\n        \n        // 招募骑士\n        function recruitKnight() {\n            if (gameState.recruitmentPoints <= 0) {\n                updateStatus('没有可用的招募点数！');\n                return;\n            }\n            \n            if (gameState.gold < unitTypes.playerKnight.cost) {\n                updateStatus('金币不足！需要60金币招募骑士');\n                return;\n            }\n            \n            // 找到合适的招募位置\n            const emptyCells = [];\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] === null && i < battlefieldSize / 2) {\n                        emptyCells.push({ row: i, col: j });\n                    }\n                }\n            }\n            \n            if (emptyCells.length > 0) {\n                const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];\n                placeUnit(randomCell.row, randomCell.col, 'playerKnight');\n                \n                // 添加招募动画\n                const cell = document.querySelector(`[data-row="${randomCell.row}"][data-col="${randomCell.col}"]`);\n                cell.classList.add('recruiting');\n                setTimeout(() => {\n                    cell.classList.remove('recruiting');\n                }, 500);\n                \n                gameState.gold -= unitTypes.playerKnight.cost;\n                gameState.recruitmentPoints--;\n                \n                updateGold();\n                updateRecruitmentPoints();\n                updateStatus('成功招募了新的骑士！');\n                \n                hideRecruitMenu();\n            } else {\n                updateStatus('没有可用的招募位置');\n            }\n        }\n        \n        // 敌军AI招募单位 - 优先招募模式\n        function aiRecruitEmergency() {\n            const emptyCells = [];\n            \n            // 只在敌军区域寻找空位\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] === null && i >= battlefieldSize / 2) {\n                        emptyCells.push({ row: i, col: j });\n                    }\n                }\n            }\n            \n            // 没有可用的招募位置，尝试在整个战场招募\n            if (emptyCells.length === 0) {\n                for (let i = 0; i < battlefieldSize; i++) {\n                    for (let j = 0; j < battlefieldSize; j++) {\n                        if (battlefield[i][j] === null) {\n                            emptyCells.push({ row: i, col: j });\n                        }\n                    }\n                }\n            }\n            \n            // 如果仍然没有可用的位置，则招募失败\n            if (emptyCells.length === 0) {\n                return false;\n            }\n            \n            // 由于单位数量不足，优先招募士兵\n            const recruitType = 'enemySoldier';\n            let recruitCost = unitTypes.enemySoldier.cost;\n            \n            // 如果金币足够，有一定概率招募骑士\n            if (gameState.enemyGold >= unitTypes.enemyKnight.cost && Math.random() > 0.7) {\n                recruitType = 'enemyKnight';\n                recruitCost = unitTypes.enemyKnight.cost;\n            }\n            \n            // 如果金币不足，招募失败\n            if (gameState.enemyGold < recruitCost) {\n                return false;\n            }\n            \n            // 尽可能靠近指挥部招募\n            let bestCell = emptyCells[0];\n            let minDistance = Infinity;\n            \n            for (const cell of emptyCells) {\n                const base = findEnemyBase();\n                if (base) {\n                    const distance = Math.abs(cell.row - base.row) + Math.abs(cell.col - base.col);\n                    if (distance < minDistance) {\n                        minDistance = distance;\n                        bestCell = cell;\n                    }\n                }\n            }\n            \n            // 招募单位\n            placeUnit(bestCell.row, bestCell.col, recruitType);\n            \n            // 添加招募动画\n            const cell = document.querySelector(`[data-row="${bestCell.row}"][data-col="${bestCell.col}"]`);\n            cell.classList.add('recruiting');\n            setTimeout(() => {\n                cell.classList.remove('recruiting');\n            }, 500);\n            \n            gameState.enemyGold -= Math.floor(recruitCost);\n            gameState.enemyRecruitmentPoints--;\n            \n            updateEnemyResources();\n            updateStatus(`⚠️ 敌军紧急招募了新的${recruitType === 'enemyKnight' ? '骑士' : '士兵'}以补充兵力！`);\n            \n            return true;\n        }\n        \n        // 敌军AI招募单位 - 正常模式\n        function aiRecruit() {\n            // 清除之前的单位\n            const emptyCells = [];\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] === null && i >= battlefieldSize / 2) {\n                        emptyCells.push({ row: i, col: j });\n                    }\n                }\n            }\n            \n            // 没有可用的招募位置\n            if (emptyCells.length === 0) return;\n            \n            // 根据当前回合数确定AI策略\n            let strategy;\n            if (gameState.round < 3) {\n                strategy = aiStrategies.defensive; // 早期保守防守\n            } else if (gameState.round < 6) {\n                strategy = aiStrategies.balanced; // 中期攻守兼备\n            } else {\n                strategy = aiStrategies.aggressive; // 后期主动进攻\n            }\n            \n            // 根据回合数调整资源生成\n            const roundMultiplier = Math.min(1.5, 1 + (gameState.round - 1) * 0.05);\n            \n            // 根据策略决定招募类型\n            let recruitType = 'enemySoldier';\n            let recruitCost = unitTypes.enemySoldier.cost;\n            \n            const soldiers = countEnemySoldiers();\n            const knights = countEnemyKnights();\n            const ratio = soldiers / Math.max(1, knights);\n            \n            // 根据策略决定招募单位类型\n            if (ratio > strategy.soldierToKnightRatio && \n                gameState.enemyGold >= unitTypes.enemyKnight.cost * roundMultiplier &&\n                Math.random() > strategy.recruitThreshold) {\n                recruitType = 'enemyKnight';\n                recruitCost = unitTypes.enemyKnight.cost;\n            }\n            \n            // 如果金币不足，招募士兵\n            if (gameState.enemyGold < recruitCost * roundMultiplier) {\n                return;\n            }\n            \n            // 找到靠近指挥部的位置\n            let bestCell = emptyCells[0];\n            let minDistance = Infinity;\n            \n            for (const cell of emptyCells) {\n                const base = findEnemyBase();\n                if (base) {\n                    const distance = Math.abs(cell.row - base.row) + Math.abs(cell.col - base.col);\n                    if (distance < minDistance) {\n                        minDistance = distance;\n                        bestCell = cell;\n                    }\n                }\n            }\n            \n            // 招募单位\n            placeUnit(bestCell.row, bestCell.col, recruitType);\n            \n            // 添加招募动画\n            const cell = document.querySelector(`[data-row="${bestCell.row}"][data-col="${bestCell.col}"]`);\n            cell.classList.add('recruiting');\n            setTimeout(() => {\n                cell.classList.remove('recruiting');\n            }, 500);\n            \n            gameState.enemyGold -= Math.floor(recruitCost * roundMultiplier);\n            gameState.enemyRecruitmentPoints--;\n            \n            updateEnemyResources();\n            updateStatus(`⚠️ 敌军招募了新的${recruitType === 'enemyKnight' ? '骑士' : '士兵'}！`);\n        }\n        \n        // 计算敌军士兵数量\n        function countEnemySoldiers() {\n            let count = 0;\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemySoldier') {\n                        count++;\n                    }\n                }\n            }\n            return count;\n        }\n        \n        // 计算敌军骑士数量\n        function countEnemyKnights() {\n            let count = 0;\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyKnight') {\n                        count++;\n                    }\n                }\n            }\n            return count;\n        }\n        \n        // 敌军AI撤退到指挥部\n        function retreatToCommandCenter(unit) {\n            // 找到最近的敌军指挥部\n            let closestBase = null;\n            let minDistance = Infinity;\n            \n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyBase') {\n                        const distance = Math.abs(unit.row - i) + Math.abs(unit.col - j);\n                        if (distance < minDistance) {\n                            minDistance = distance;\n                            closestBase = { row: i, col: j };\n                        }\n                    }\n                }\n            }\n            \n            if (closestBase) {\n                // 找到距离指挥部最近的空位\n                let bestRow = unit.row;\n                let bestCol = unit.col;\n                let distanceToBase = Infinity;\n                \n                // 检查所有可能的位置\n                for (let row = 0; row < battlefieldSize; row++) {\n                    for (let col = 0; col < battlefieldSize; col++) {\n                        if (battlefield[row][col] === null) {\n                            const distance = Math.abs(row - closestBase.row) + Math.abs(col - closestBase.col);\n                            if (distance < distanceToBase) {\n                                distanceToBase = distance;\n                                bestRow = row;\n                                bestCol = col;\n                            }\n                        }\n                    }\n                }\n                \n                // 如果当前位置不是离指挥部最近的空位，则移动\n                if (bestRow !== unit.row || bestCol !== unit.col) {\n                    // 清除原位置\n                    battlefield[unit.row][unit.col] = null;\n                    updateCell(unit.row, unit.col);\n                    \n                    // 设置新位置\n                    unit.row = bestRow;\n                    unit.col = bestCol;\n                    battlefield[bestRow][bestCol] = unit;\n                    \n                    updateCell(bestRow, bestCol);\n                }\n            }\n        }\n        \n        // 敌军AI回合\n        function aiTurn() {\n            const enemyUnits = [];\n            \n            // 收集所有敌方单位\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type.startsWith('enemy')) {\n                        enemyUnits.push(battlefield[i][j]);\n                    }\n                }\n            }\n            \n            // 检查敌军数量，决定是否需要紧急招募\n            if (gameState.enemyUnits < gameState.enemyMinUnits) {\n                updateStatus(`⚠️ 敌军兵力不足(${gameState.enemyUnits}个)，开始紧急招募单位...`);\n                \n                // 尝试紧急招募\n                setTimeout(() => {\n                    if (aiRecruitEmergency()) {\n                        // 招募成功，继续执行单位行动\n                        setTimeout(() => {\n                            executeEnemyActions(enemyUnits);\n                        }, 500);\n                    } else {\n                        // 招募失败，敌人撤退\n                        setTimeout(() => {\n                            for (let i = 0; i < enemyUnits.length; i++) {\n                                const unit = enemyUnits[i];\n                                \n                                if (unit.movement > 0) {\n                                    setTimeout(() => {\n                                        retreatToCommandCenter(unit);\n                                    }, i * 300);\n                                }\n                            }\n                            \n                            // 结束AI回合\n                            setTimeout(() => {\n                                endTurn();\n                            }, enemyUnits.length * 300 + 1000);\n                        }, 500);\n                    }\n                }, 500);\n                \n                return;\n            }\n            \n            // 显示敌军行动提示\n            updateStatus('⚔️ 敌军正在行动...');\n            \n            // 敌军招募单位\n            setTimeout(() => {\n                aiRecruit();\n            }, 500);\n            \n            // 延迟执行单位行动\n            setTimeout(() => {\n                executeEnemyActions(enemyUnits);\n            }, 1000);\n        }\n        \n        // 执行敌方单位行动\n        function executeEnemyActions(enemyUnits) {\n            // 检查是否需要保护指挥部\n            let protectBase = false;\n            \n            // 检查是否有玩家单位靠近指挥部\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type.startsWith('player')) {\n                        const base = findEnemyBase();\n                        if (base) {\n                            const distance = Math.abs(i - base.row) + Math.abs(j - base.col);\n                            if (distance <= 3) {\n                                protectBase = true;\n                                break;\n                            }\n                        }\n                    }\n                }\n            }\n            \n            // 根据当前回合数确定AI策略\n            let strategy;\n            if (gameState.round < 3) {\n                strategy = aiStrategies.defensive; // 早期保守防守\n            } else if (gameState.round < 6) {\n                strategy = aiStrategies.balanced; // 中期攻守兼备\n            } else {\n                strategy = aiStrategies.aggressive; // 后期主动进攻\n            }\n            \n            // 根据敌军数量调整策略\n            if (gameState.enemyUnits >= gameState.enemyMaxUnits) {\n                // 敌军数量充足，可以主动进攻\n                strategy.baseDefensePriority = 0.3;\n            }\n            \n            // 如果需要保护指挥部的概率增加\n            if (protectBase) {\n                strategy.baseDefensePriority = Math.max(0.8, strategy.baseDefensePriority);\n            }\n            \n            // 每个敌方单位行动\n            for (let i = 0; i < enemyUnits.length; i++) {\n                const unit = enemyUnits[i];\n                \n                if (unit.movement > 0) {\n                    // 根据策略决定行动\n                    if (Math.random() < strategy.baseDefensePriority && protectBase) {\n                        // 保护指挥部\n                        setTimeout(() => {\n                            protectCommandCenter(unit);\n                        }, i * 300 + 1000);\n                    } else {\n                        // 优先攻击近处的目标\n                        const adjacentTargets = findAdjacentEnemies(unit.row, unit.col, ['playerSoldier', 'playerKnight']);\n                        \n                        if (adjacentTargets.length > 0) {\n                            // 攻击附近的玩家单位\n                            setTimeout(() => {\n                                performEnemyAttack(unit, adjacentTargets[0]);\n                            }, i * 300 + 1000);\n                        } else if (unit.type === 'enemyKnight' && countEnemySoldiers() > countEnemyKnights() * strategy.soldierToKnightRatio) {\n                            // 骑兵向指挥部移动\n                            setTimeout(() => {\n                                moveTowardsCommandCenter(unit);\n                            }, i * 300 + 1000);\n                        } else if (strategy.baseDefensePriority < 0.5) {\n                            // 如果采用进攻策略，向玩家领地移动\n                            setTimeout(() => {\n                                moveTowardsPlayer(unit);\n                            }, i * 300 + 1000);\n                        }\n                    }\n                }\n            }\n            \n            // 结束AI回合\n            setTimeout(() => {\n                endTurn();\n            }, enemyUnits.length * 300 + 2000);\n        }\n        \n        // 查找敌方指挥部\n        function findEnemyBase() {\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyBase') {\n                        return { row: i, col: j };\n                    }\n                }\n            }\n            return null;\n        }\n        \n        // 保护指挥部\n        function protectCommandCenter(unit) {\n            const base = findEnemyBase();\n            if (!base) return;\n            \n            // 如果单位已经在指挥部周围，优先守住\n            const distance = Math.abs(unit.row - base.row) + Math.abs(unit.col - base.col);\n            if (distance <= 2) {\n                // 检查是否有玩家单位在附近\n                const nearbyPlayers = findAdjacentEnemies(base.row, base.col, ['playerSoldier', 'playerKnight']);\n                if (nearbyPlayers.length > 0) {\n                    // 攻击靠近指挥部的玩家单位\n                    performEnemyAttack(unit, nearbyPlayers[0]);\n                    return;\n                }\n                return;\n            }\n            \n            // 向指挥部移动\n            moveTowardsCommandCenter(unit);\n        }\n        \n        // 向指挥部移动\n        function moveTowardsCommandCenter(unit) {\n            const base = findEnemyBase();\n            if (!base) return;\n            \n            let bestRow = unit.row;\n            let bestCol = unit.col;\n            let minDistance = Infinity;\n            \n            // 计算向指挥部靠近的移动\n            for (let row = 0; row < battlefieldSize; row++) {\n                for (let col = 0; col < battlefieldSize; col++) {\n                    if (battlefield[row][col] === null && canMove(unit, row, col)) {\n                        const distance = Math.abs(row - base.row) + Math.abs(col - base.col);\n                        if (distance < minDistance) {\n                            minDistance = distance;\n                            bestRow = row;\n                            bestCol = col;\n                        }\n                    }\n                }\n            }\n            \n            // 移动单位\n            if (bestRow !== unit.row || bestCol !== unit.col) {\n                battlefield[unit.row][unit.col] = null;\n                updateCell(unit.row, unit.col);\n                \n                unit.row = bestRow;\n                unit.col = bestCol;\n                battlefield[bestRow][bestCol] = unit;\n                \n                updateCell(bestRow, bestCol);\n            }\n        }\n        \n        // 寻找相邻的敌人\n        function findAdjacentEnemies(row, col, enemyTypes) {\n            const enemies = [];\n            \n            const directions = [\n                { row: -1, col: 0 },\n                { row: 1, col: 0 },\n                { row: 0, col: -1 },\n                { row: 0, col: 1 }\n            ];\n            \n            directions.forEach(dir => {\n                const newRow = row + dir.row;\n                const newCol = col + dir.col;\n                \n                if (newRow >= 0 && newRow < battlefieldSize && \n                    newCol >= 0 && newCol < battlefieldSize) {\n                    const unit = battlefield[newRow][newCol];\n                    if (unit && enemyTypes.includes(unit.type)) {\n                        enemies.push(unit);\n                    }\n                }\n            });\n            \n            return enemies;\n        }\n        \n        // 执行敌方攻击\n        function performEnemyAttack(attacker, defender) {\n            let damage = attacker.power;\n            \n            // 检查防御状态\n            if (defender.defending) {\n                damage = Math.floor(damage / 2);\n            }\n            \n            defender.health -= damage;\n            updateCell(defender.row, defender.col);\n            \n            if (defender.health <= 0) {\n                // 玩家单位被消灭\n                battlefield[defender.row][defender.col] = null;\n                updateCell(defender.row, defender.col);\n                \n                gameState.playerUnits--;\n                updateUnits();\n                \n                updateStatus(`${attacker.name}击败了你的${defender.name}！`);\n                \n                // 检查游戏是否结束\n                checkGameOver();\n            } else {\n                updateStatus(`敌人攻击，你的${defender.name}剩余生命: ${defender.health}/${defender.maxHealth}`);\n            }\n        }\n        \n        // 向玩家领地移动\n        function moveTowardsPlayer(unit) {\n            let bestRow = unit.row;\n            let bestCol = unit.col;\n            let minDistance = Infinity;\n            \n            // 计算最佳移动位置\n            for (let row = 0; row < battlefieldSize; row++) {\n                for (let col = 0; col < battlefieldSize; col++) {\n                    if (battlefield[row][col] === null && canMove(unit, row, col)) {\n                        // 寻找最近的玩家单位\n                        let closestDistance = Infinity;\n                        \n                        for (let pRow = 0; pRow < battlefieldSize; pRow++) {\n                            for (let pCol = 0; pCol < battlefieldSize; pCol++) {\n                                const target = battlefield[pRow][pCol];\n                                if (target && (target.type === 'playerSoldier' || target.type === 'playerKnight')) {\n                                    const distance = Math.abs(row - pRow) + Math.abs(col - pCol);\n                                    closestDistance = Math.min(closestDistance, distance);\n                                }\n                            }\n                        }\n                        \n                        if (closestDistance < minDistance) {\n                            minDistance = closestDistance;\n                            bestRow = row;\n                            bestCol = col;\n                        }\n                    }\n                }\n            }\n            \n            // 移动单位\n            if (bestRow !== unit.row || bestCol !== unit.col) {\n                battlefield[unit.row][unit.col] = null;\n                updateCell(unit.row, unit.col);\n                \n                unit.row = bestRow;\n                unit.col = bestCol;\n                battlefield[bestRow][bestCol] = unit;\n                \n                updateCell(bestRow, bestCol);\n            }\n        }\n        \n        // 结束回合\n        function endTurn() {\n            gameState.playerTurn = !gameState.playerTurn;\n            gameState.selectedUnit = null;\n            gameState.mode = 'normal';\n            \n            // 重置所有单位的移动状态\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    const unit = battlefield[i][j];\n                    if (unit && (unit.type === 'playerSoldier' || unit.type === 'playerKnight')) {\n                        unit.moved = false;\n                        unit.defending = false;\n                        updateCell(i, j);\n                    }\n                }\n            }\n            \n            // 清除所有可能的移动标记\n            document.querySelectorAll('.possible-move').forEach(cell => {\n                cell.classList.remove('possible-move');\n            });\n            document.querySelectorAll('.base-target').forEach(cell => {\n                cell.classList.remove('base-target');\n            });\n            \n            if (gameState.playerTurn) {\n                // 每回合增加资源\n                gameState.gold += 20;\n                gameState.recruitmentPoints++;\n                \n                updateGold();\n                updateRecruitmentPoints();\n                gameState.round++;\n                updateRound();\n                updateStatus('你的回合 - 获得20金币和1个招募点数');\n            } else {\n                gameState.enemyGold += 15;\n                gameState.enemyRecruitmentPoints++;\n                \n                updateEnemyResources();\n                updateStatus('敌人回合 - 敌军获得15金币和1个招募点数');\n                aiTurn();\n            }\n            \n            checkGameOver();\n        }\n        \n        // 更新敌方资源显示\n        function updateEnemyResources() {\n            document.getElementById('enemyGold').textContent = gameState.enemyGold;\n            document.getElementById('enemyRecruitmentPoints').textContent = gameState.enemyRecruitmentPoints;\n        }\n        \n        // 检查游戏是否结束\n        function checkGameOver() {\n            // 检查玩家单位是否全部被消灭\n            if (gameState.playerUnits === 0) {\n                gameOver(false);\n                return;\n            }\n            \n            // 检查敌军指挥部是否被占领\n            let baseExists = false;\n            for (let i = 0; i < battlefieldSize; i++) {\n                for (let j = 0; j < battlefieldSize; j++) {\n                    if (battlefield[i][j] && battlefield[i][j].type === 'enemyBase') {\n                        baseExists = true;\n                        break;\n                    }\n                }\n            }\n            \n            if (!baseExists) {\n                gameOver(true);\n                return;\n            }\n        }\n        \n        // 游戏结束\n        function gameOver(playerWon) {\n            gameState.gameOver = true;\n            \n            const overlay = document.getElementById('overlay');\n            const messageDiv = document.createElement('div');\n            messageDiv.className = 'message active';\n            messageDiv.innerHTML = `\n                <h2 style="color: ${playerWon ? '#ff9800' : '#f44336'}; margin-bottom: 20px;">${playerWon ? '🎉 胜利！' : '💥 失败'}</h2>\n                <p style="margin-bottom: 10px; font-size: 1.1rem;">${playerWon ? '恭喜！你成功占领了敌军指挥部，赢得了战争！' : '你的兵团被击败了，但不要放弃，再试一次！'}</p>\n                <div style="background-color: #f5f5f5; padding: 15px; border-radius: 10px; margin: 15px 0;">\n                    <p style="margin: 5px 0;">最终得分：${gameState.score}</p>\n                    <p style="margin: 5px 0;">剩余金币：${gameState.gold}</p>\n                    <p style="margin: 5px 0;">存活单位：${gameState.playerUnits}</p>\n                    <p style="margin: 5px 0;">游戏回合：${gameState.round}</p>\n                </div>\n                <button onclick="restartGame()" style="padding: 12px 25px; background-color: #4caf50; color: white; border: none; border-radius: 8px; font-size: 1.1rem; cursor: pointer;">重新开始</button>\n            `;\n            \n            overlay.classList.add('active');\n            document.body.appendChild(messageDiv);\n        }\n        \n        // 重新开始游戏\n        function restartGame() {\n            // 移除可能存在的消息框\n            const message = document.querySelector('.message');\n            if (message) {\n                message.remove();\n            }\n            \n            gameState.round = 1;\n            gameState.score = 0;\n            gameState.playerUnits = 0;\n            gameState.enemyUnits = 0;\n            gameState.gold = 100;\n            gameState.enemyGold = 80;\n            gameState.recruitmentPoints = 3;\n            gameState.enemyRecruitmentPoints = 2;\n            gameState.selectedUnit = null;\n            gameState.mode = 'normal';\n            gameState.playerTurn = true;\n            gameState.gameOver = false;\n            \n            updateRound();\n            updateScore();\n            updateUnits();\n            updateGold();\n            updateRecruitmentPoints();\n            updateEnemyResources();\n            \n            const overlay = document.getElementById('overlay');\n            overlay.classList.remove('active');\n            \n            initBattlefield();\n            updateStatus('🎯 新战役开始！你的目标是占领敌军指挥部。敌军少于5个时会优先招募单位！');\n        }\n        \n        // 更新UI\n        function updateStatus(text) {\n            document.getElementById('statusText').textContent = text;\n        }\n        \n        function updateRound() {\n            document.getElementById('round').textContent = gameState.round;\n        }\n        \n        function updateScore() {\n            document.getElementById('score').textContent = gameState.score;\n        }\n        \n        function updateUnits() {\n            document.getElementById('playerUnits').textContent = gameState.playerUnits;\n            document.getElementById('enemyUnits').textContent = gameState.enemyUnits;\n        }\n        \n        function updateGold() {\n            document.getElementById('gold').textContent = gameState.gold;\n        }\n        \n        function updateRecruitmentPoints() {\n            document.getElementById('recruitmentPoints').textContent = gameState.recruitmentPoints;\n        }\n        \n        // 键盘事件处理\n        document.addEventListener('keydown', e => {\n            if (!gameState.playerTurn || gameState.gameOver) return;\n            \n            const key = e.key.toLowerCase();\n            const selected = gameState.selectedUnit;\n            \n            switch(key) {\n                case ' ':\n                    e.preventDefault();\n                    // 空格键选择/取消选择单位\n                    gameState.selectedUnit = null;\n                    for (let i = 0; i < battlefieldSize; i++) {\n                        for (let j = 0; j < battlefieldSize; j++) {\n                            updateCell(i, j);\n                        }\n                    }\n                    document.querySelectorAll('.possible-move').forEach(cell => {\n                        cell.classList.remove('possible-move');\n                    });\n                    document.querySelectorAll('.base-target').forEach(cell => {\n                        cell.classList.remove('base-target');\n                    });\n                    break;\n                case 'r':\n                    e.preventDefault();\n                    showRecruitMenu();\n                    break;\n                case 'm':\n                    e.preventDefault();\n                    if (selected) {\n                        gameState.mode = 'move';\n                        updateStatus('使用方向键或WASD移动单位');\n                    }\n                    break;\n                case 'a':\n                    e.preventDefault();\n                    if (selected) {\n                        gameState.mode = 'attack';\n                        updateStatus('选择攻击目标');\n                    }\n                    break;\n                case 'd':\n                    e.preventDefault();\n                    if (selected) {\n                        selected.defending = true;\n                        updateStatus(`${selected.name}进入防御姿态`);\n                    }\n                    break;\n                case 'e':\n                    e.preventDefault();\n                    endTurn();\n                    break;\n                case '1':\n                    e.preventDefault();\n                    recruitSoldier();\n                    break;\n                case '2':\n                    e.preventDefault();\n                    recruitKnight();\n                    break;\n                case 'escape':\n                    e.preventDefault();\n                    hideRecruitMenu();\n                    break;\n                case 'arrowdown':\n                case 's':\n                    e.preventDefault();\n                    // 下键快速进入下一回合\n                    if (!selected) {\n                        // 如果没有选中单位，直接进入下一回合\n                        updateStatus('跳过行动，进入下一回合');\n                        endTurn();\n                    }\n                    break;\n                case 'arrowup':\n                case 'w':\n                    e.preventDefault();\n                    if (selected) {\n                        const directions = [\n                            { row: -1, col: 0 },\n                            { row: -2, col: 0 },\n                            { row: 0, col: -1 },\n                            { row: 0, col: -2 }\n                        ];\n                        \n                        for (const dir of directions) {\n                            const newRow = selected.row + dir.row;\n                            const newCol = selected.col + dir.col;\n                            \n                            if (gameState.mode === 'move' && canMove(selected, newRow, newCol)) {\n                                moveUnit(newRow, newCol);\n                                return;\n                            }\n                        }\n                    }\n                    break;\n                case 'arrowleft':\n                    e.preventDefault();\n                    if (selected) {\n                        const directions = [\n                            { row: 0, col: -1 },\n                            { row: 0, col: -2 },\n                            { row: -1, col: 0 },\n                            { row: -2, col: 0 }\n                        ];\n                        \n                        for (const dir of directions) {\n                            const newRow = selected.row + dir.row;\n                            const newCol = selected.col + dir.col;\n                            \n                            if (gameState.mode === 'move' && canMove(selected, newRow, newCol)) {\n                                moveUnit(newRow, newCol);\n                                return;\n                            }\n                        }\n                    }\n                    break;\n                case 'arrowright':\n                    e.preventDefault();\n                    if (selected) {\n                        const directions = [\n                            { row: 0, col: 1 },\n                            { row: 0, col: 2 },\n                            { row: 1, col: 0 },\n                            { row: 2, col: 0 }\n                        ];\n                        \n                        for (const dir of directions) {\n                            const newRow = selected.row + dir.row;\n                            const newCol = selected.col + dir.col;\n                            \n                            if (gameState.mode === 'move' && canMove(selected, newRow, newCol)) {\n                                moveUnit(newRow, newCol);\n                                return;\n                            }\n                        }\n                    }\n                    break;\n            }\n        });\n        \n        // 按钮事件处理\n        document.getElementById('recruitBtn').addEventListener('click', showRecruitMenu);\n        \n        document.getElementById('moveBtn').addEventListener('click', () => {\n            if (gameState.playerTurn && !gameState.gameOver) {\n                if (gameState.selectedUnit) {\n                    gameState.mode = 'move';\n                    updateStatus('使用方向键或WASD移动单位');\n                } else {\n                    updateStatus('请先选择一个单位');\n                }\n            }\n        });\n        \n        document.getElementById('attackBtn').addEventListener('click', () => {\n            if (gameState.playerTurn && !gameState.gameOver) {\n                if (gameState.selectedUnit) {\n                    gameState.mode = 'attack';\n                    updateStatus('选择攻击目标');\n                } else {\n                    updateStatus('请先选择一个单位');\n                }\n            }\n        });\n        \n        document.getElementById('defendBtn').addEventListener('click', () => {\n            if (gameState.playerTurn && !gameState.gameOver && gameState.selectedUnit) {\n                gameState.selectedUnit.defending = true;\n                updateStatus(`${gameState.selectedUnit.name}进入防御姿态`);\n            }\n        });\n        \n        document.getElementById('endTurnBtn').addEventListener('click', () => {\n            if (gameState.playerTurn && !gameState.gameOver) {\n                endTurn();\n            }\n        });\n        \n        document.getElementById('recruitSoldier').addEventListener('click', recruitSoldier);\n        \n        document.getElementById('recruitKnight').addEventListener('click', recruitKnight);\n        \n        document.getElementById('cancelRecruitBtn').addEventListener('click', hideRecruitMenu);\n        \n        // 窗口大小改变时调整界面\n        window.addEventListener('resize', () => {\n            // 可以在这里添加响应式调整逻辑\n        });\n        \n        // 初始化游戏\n        initBattlefield();\n        updateStatus('🎯 新战役开始！你的目标是占领敌军指挥部。敌军少于5个时会优先招募单位！');\n    </script>\n</body>\n</html>			\N	\N	\N	2025-11-25 13:58:53.569	2025-11-27 13:22:32.268	