1e65b221-f7fa-48f6-8fab-8c088bf2f2d6	22365e90-5b03-40d3-ae53-715895e9c691	《寡人之于国也》知识测验	\N	<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="UTF-8">\n<title>《寡人之于国也》知识测验</title>\n<style>\n    \n</style>\n</head>\n<body>\n<div class="container">\n    <h1>《寡人之于国也》知识测验</h1>\n    <form id="quizForm">\n        <!-- 题目会通过 JavaScript 动态插入 -->\n    </form>\n    <button id="submitBtn">交卷</button>\n    <div id="result"></div>\n</div>\n\n<script>\n/* --------------- 题库 --------------- */\n\n</script>\n</body>\n</html>	body{font-family: "Helvetica Neue",Helvetica,Arial,sans-serif;background:#f8f9fa;margin:0;padding:0;}\n    .container{max-width:800px;margin:auto;padding:20px;background:#fff;box-shadow:0 0 10px rgba(0,0,0,.1);}\n    h1{text-align:center;color:#2c3e50;}\n    .question{margin:20px 0;padding:15px;border:1px solid #e0e0e0;border-radius:5px;background:#fafafa;}\n    .question h3{margin:0 0 10px;font-size:1.1em;color:#34495e;}\n    .options label{display:block;margin:5px 0;cursor:pointer;}\n    .options input{margin-right:8px;}\n    .feedback{margin-top:8px;font-size:.9em;}\n    .correct{color:#27ae60;}\n    .wrong{color:#c0392b;}\n    #submitBtn{display:block;width:100%;padding:12px;background:#3498db;color:#fff;border:none;border-radius:5px;font-size:1em;cursor:pointer;margin-top:30px;}\n    #submitBtn:hover{background:#2980b9;}\n    #result{margin-top:30px;padding:20px;background:#ecf0f1;border-radius:5px;text-align:center;font-size:1.2em;}	const questions = [\n    {\n        q: "《寡人之于国也》出自哪本书？",\n        o: ["《论语》", "《孟子》", "《庄子》", "《韩非子》"],\n        a: 1\n    },\n    {\n        q: "孟子主张的治国理念最核心的词语是？",\n        o: ["法家", "君主专制", "仁政", "兼爱"],\n        a: 2\n    },\n    {\n        q: "孟子提出的民本思想是：",\n        o: ["民为贵，社稷次之，君为轻", "君为贵，民为次，社稷为轻", "社稷为贵，民为轻，君为次", "民为轻，君为贵，社稷为次"],\n        a: 0\n    },\n    {\n        q: "孟子认为王道的起点是？",\n        o: ["让百姓安居乐业", "使民养生丧死无憾", "让诸侯服从", "推进商业贸易"],\n        a: 1\n    },\n    {\n        q: "文中“狗彘食人食而不知检”所反映的社会现象是？",\n        o: ["统治者不关心百姓生死", "动物灾害频发", "百姓对君主失望", "贵族之间的争斗"],\n        a: 0\n    },\n    {\n        q: "孟子批评梁惠王的“移民”“移粟”做法是因为它们",\n        o: ["没有解决根本问题，不能使民养生丧死无憾", "太过于奢侈浪费", "致使国家财政赤字", "导致军队兵力下降"],\n        a: 0\n    },\n    {\n        q: "下列哪句是孟子用来讽刺梁惠王的比喻？",\n        o: ["五十步笑百步", "千里迢迢", "画蛇添足", "杯弓蛇影"],\n        a: 0\n    },\n    {\n        q: "孟子在文中指出的王道措施不包括下面哪一项？",\n        o: ["养生丧死无憾", "春耕秋收", "庙堂礼义教育", "强制徭役"],\n        a: 3\n    },\n    {\n        q: "“弃甲曳兵而走”中“曳兵而走”的意思是？",\n        o: ["拖着武器撤退", "用兵打仗", "训练士兵", "收割庄稼"],\n        a: 0\n    },\n    {\n        q: "“王无罪岁”中的“罪岁”指的是？",\n        o: ["把罪责归咎于年成不好", "君主的年龄", "国家的灾年", "人民的错误"],\n        a: 0\n    },\n    {\n        q: "在寡人之于国也里使用的主要论证方法是？",\n        o: ["归纳法", "演绎法", "类比法", "实验法"],\n        a: 3\n    },\n    {\n        q: "以下哪句话最能概括孟子的王道政治？",\n        o: ["以民为本，施行仁政", "以武力扩张领土", "以税收为根本", "以礼乐为唯一手段"],\n        a: 0\n    },\n    {\n        q: "孟子认为“七十者衣帛食肉，黎民不饥不寒”指的是？",\n        o: ["富人奢华，贫民安稳", "富裕阶层的生活状态与普通百姓的富足", "只有贵族才能享受食物", "贫富差距的扩大"],\n        a: 1\n    },\n    {\n        q: "文中“直不百步耳，是亦走也”是对哪句话的解释？",\n        o: ["五十步笑百步", "不违农时", "五亩之宅", "拿刀杀人"],\n        a: 0\n    },\n    {\n        q: "孟子在《寡人之于国也》中提到的“七十者”主要指的是？",\n        o: ["七十岁以上的老年人", "七十种粮食作物", "七十位官员", "七十个兄弟"],\n        a: 0\n    },\n    {\n        q: "谁是世界上最好的人？",\n        o: ["杰哥", "迁巡", "桐妹", "大黄"],\n        a: 2\n    }\n];\n\n/* --------------- 渲染题目 --------------- */\nconst form = document.getElementById('quizForm');\n\nquestions.forEach((item, idx) => {\n    const div = document.createElement('div');\n    div.className = 'question';\n    div.id = `q${idx}`;\n\n    const title = document.createElement('h3');\n    title.textContent = `第 ${idx + 1} 题：${item.q}`;\n    div.appendChild(title);\n\n    const optDiv = document.createElement('div');\n    optDiv.className = 'options';\n    item.o.forEach((opt, oIdx) => {\n        const label = document.createElement('label');\n        const radio = document.createElement('input');\n        radio.type = 'radio';\n        radio.name = `ans${idx}`;\n        radio.value = oIdx;\n        label.appendChild(radio);\n        label.appendChild(document.createTextNode(opt));\n        optDiv.appendChild(label);\n    });\n    div.appendChild(optDiv);\n\n    const fb = document.createElement('div');\n    fb.className = 'feedback';\n    div.appendChild(fb);\n\n    form.appendChild(div);\n});\n\n/* --------------- 检查答案 --------------- */\ndocument.getElementById('submitBtn').addEventListener('click', function () {\n    let score = 0;\n    questions.forEach((item, idx) => {\n        const selected = document.querySelector(`input[name="ans${idx}"]:checked`);\n        const feedbackDiv = document.querySelector(`#q${idx} .feedback`);\n        feedbackDiv.innerHTML = '';   // 先清空\n\n        if (!selected) { // 未作答\n            feedbackDiv.innerHTML = `<span class="wrong">未作答，正确答案：<strong>${item.o[item.a]}</strong></span>`;\n            return;\n        }\n\n        const userAns = parseInt(selected.value, 10);\n        if (userAns === item.a) {\n            score++;\n            feedbackDiv.innerHTML = `<span class="correct">答对啦！</span>`;\n        } else {\n            feedbackDiv.innerHTML = `<span class="wrong">答错了，正确答案：<strong>${item.o[item.a]}</strong></span>`;\n        }\n    });\n\n    const resultDiv = document.getElementById('result');\n    resultDiv.innerHTML = `您的总得分是 <strong>${score}</strong> / ${questions.length} 分`;\n    // 防止二次点击后再次改变分数\n    this.disabled = true;\n});	\N	\N	\N	2025-11-26 04:56:24.915	2025-11-28 12:10:04.073	语言	t
b7b454b8-eeec-42c9-8c95-4dee30c708dd	b43124b2-f848-4f92-8b18-a36fc7ab57af	算命	\N	<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">\n    <title>神秘算命师 - 探索你的命运</title>\n    <style>\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n            font-family: 'Georgia', serif;\n        }\n        \n        body {\n            background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);\n            min-height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            padding: 20px;\n            color: #333;\n        }\n        \n        .game-container {\n            width: 100%;\n            max-width: 800px;\n            background: rgba(255, 255, 255, 0.9);\n            border-radius: 20px;\n            box-shadow: 0 20px 50px rgba(0, 0, 0, 0.1);\n            overflow: hidden;\n            position: relative;\n        }\n        \n        .game-header {\n            background: linear-gradient(135deg, #6a11cb 0%, #2575fc 100%);\n            color: white;\n            padding: 30px;\n            text-align: center;\n            position: relative;\n        }\n        \n        .game-title {\n            font-size: 2.5em;\n            margin-bottom: 10px;\n            text-shadow: 0 2px 5px rgba(0, 0, 0, 0.2);\n        }\n        \n        .game-subtitle {\n            font-size: 1.2em;\n            opacity: 0.9;\n        }\n        \n        .crystal-ball {\n            width: 120px;\n            height: 120px;\n            background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.8), rgba(106, 17, 203, 0.4));\n            border-radius: 50%;\n            position: absolute;\n            bottom: -60px;\n            left: 50%;\n            transform: translateX(-50%);\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            overflow: hidden;\n        }\n        \n        .crystal-ball::before {\n            content: '';\n            position: absolute;\n            width: 100px;\n            height: 100px;\n            background: radial-gradient(circle at 40% 40%, rgba(255, 255, 255, 0.9), rgba(106, 17, 203, 0.3));\n            border-radius: 50%;\n            filter: blur(2px);\n        }\n        \n        .game-area {\n            padding: 60px 30px 30px;\n            min-height: 400px;\n        }\n        \n        .fortune-teller {\n            text-align: center;\n            margin-bottom: 30px;\n        }\n        \n        .fortune-teller-img {\n            width: 200px;\n            height: 200px;\n            margin: 0 auto 20px;\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            border-radius: 50%;\n            position: relative;\n            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);\n            overflow: hidden;\n        }\n        \n        .fortune-teller-img::before {\n            content: '🔮';\n            position: absolute;\n            font-size: 100px;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            filter: drop-shadow(0 0 10px rgba(255, 255, 255, 0.7));\n        }\n        \n        .fortune-teller-text {\n            font-size: 1.3em;\n            line-height: 1.6;\n            color: #555;\n            margin-bottom: 30px;\n            min-height: 80px;\n        }\n        \n        .question-container {\n            display: none;\n            animation: fadeIn 0.5s ease-in-out;\n        }\n        \n        @keyframes fadeIn {\n            from { opacity: 0; transform: translateY(20px); }\n            to { opacity: 1; transform: translateY(0); }\n        }\n        \n        .question {\n            font-size: 1.4em;\n            color: #444;\n            margin-bottom: 25px;\n            text-align: center;\n        }\n        \n        .options {\n            display: flex;\n            flex-direction: column;\n            gap: 15px;\n        }\n        \n        .option {\n            background: white;\n            border: 2px solid #e0e0e0;\n            border-radius: 12px;\n            padding: 15px 25px;\n            font-size: 1.1em;\n            cursor: pointer;\n            transition: all 0.3s ease;\n            text-align: center;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .option:hover, .option:focus {\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            color: white;\n            border-color: transparent;\n            transform: translateY(-3px);\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.1);\n            outline: none;\n        }\n        \n        .option::before {\n            content: '';\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 0;\n            height: 100%;\n            background: rgba(255, 255, 255, 0.2);\n            transition: width 0.3s ease;\n        }\n        \n        .option:hover::before {\n            width: 100%;\n        }\n        \n        .start-button, .restart-button {\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            color: white;\n            border: none;\n            border-radius: 50px;\n            padding: 15px 40px;\n            font-size: 1.2em;\n            cursor: pointer;\n            transition: all 0.3s ease;\n            display: block;\n            margin: 20px auto;\n            box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);\n        }\n        \n        .start-button:hover, .restart-button:hover, .start-button:focus, .restart-button:focus {\n            transform: translateY(-3px);\n            box-shadow: 0 8px 20px rgba(102, 126, 234, 0.5);\n            outline: none;\n        }\n        \n        .result-container {\n            display: none;\n            text-align: center;\n            animation: fadeIn 0.8s ease-in-out;\n        }\n        \n        .result-title {\n            font-size: 2em;\n            color: #6a11cb;\n            margin-bottom: 20px;\n        }\n        \n        .result-image {\n            width: 150px;\n            height: 150px;\n            margin: 0 auto 25px;\n            background: #f5f7fa;\n            border-radius: 50%;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            font-size: 80px;\n            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);\n        }\n        \n        .result-text {\n            font-size: 1.3em;\n            line-height: 1.6;\n            color: #555;\n            margin-bottom: 30px;\n            padding: 20px;\n            background: rgba(106, 17, 203, 0.05);\n            border-radius: 12px;\n        }\n        \n        .progress-container {\n            width: 100%;\n            height: 6px;\n            background: #e0e0e0;\n            border-radius: 3px;\n            margin-bottom: 25px;\n            overflow: hidden;\n        }\n        \n        .progress-bar {\n            height: 100%;\n            background: linear-gradient(90deg, #667eea 0%, #764ba2 100%);\n            width: 0;\n            transition: width 0.5s ease;\n        }\n        \n        .stars {\n            color: #ffd700;\n            font-size: 1.5em;\n            margin: 15px 0;\n        }\n        \n        @media (max-width: 768px) {\n            .game-title {\n                font-size: 2em;\n            }\n            \n            .question {\n                font-size: 1.2em;\n            }\n            \n            .options {\n                gap: 10px;\n            }\n            \n            .option {\n                padding: 12px 20px;\n                font-size: 1em;\n            }\n        }\n    </style>\n</head>\n<body>\n    <div class="game-container">\n        <div class="game-header">\n            <h1 class="game-title">神秘算命师</h1>\n            <p class="game-subtitle">探索你未知的命运</p>\n            <div class="crystal-ball"></div>\n        </div>\n        \n        <div class="game-area">\n            <div class="fortune-teller">\n                <div class="fortune-teller-img"></div>\n                <div class="fortune-teller-text">我是一位古老的算命师，能够窥见你命运的轮盘...</div>\n            </div>\n            \n            <div class="start-screen">\n                <p style="text-align: center; font-size: 1.2em; margin-bottom: 30px; color: #666;">\n                    准备好了解你的命运了吗？回答几个简单的问题，我将为你揭示未来。\n                </p>\n                <button class="start-button" id="startButton">开始算命</button>\n            </div>\n            \n            <div class="progress-container">\n                <div class="progress-bar" id="progressBar"></div>\n            </div>\n            \n            <div class="question-container" id="questionContainer">\n                <div class="question" id="questionText"></div>\n                <div class="options" id="optionsContainer"></div>\n            </div>\n            \n            <div class="result-container" id="resultContainer">\n                <div class="result-title">你的命运已揭晓</div>\n                <div class="result-image" id="resultImage"></div>\n                <div class="result-text" id="resultText"></div>\n                <div class="stars" id="stars"></div>\n                <button class="restart-button" id="restartButton">再算一次</button>\n            </div>\n        </div>\n    </div>\n\n    <script>\n        // 游戏数据\n        const gameData = {\n            questions: [\n                {\n                    question: "当你面临重要决定时，你通常会？",\n                    options: [\n                        { text: "依靠直觉和内心感受", values: { career: 2, love: 1, finance: 1, luck: 3 } },\n                        { text: "理性分析后决定", values: { career: 3, love: 1, finance: 3, luck: 1 } },\n                        { text: "寻求他人的建议", values: { career: 1, love: 3, finance: 1, luck: 2 } },\n                        { text: "随缘顺其自然", values: { career: 2, love: 2, finance: 1, luck: 3 } }\n                    ]\n                },\n                {\n                    question: "你认为哪种颜色最能代表你的内心？",\n                    options: [\n                        { text: "深紫色 - 神秘与智慧", values: { career: 2, love: 1, finance: 1, luck: 2 } },\n                        { text: "红色 - 热情与活力", values: { career: 1, love: 3, finance: 2, luck: 1 } },\n                        { text: "蓝色 - 平静与理性", values: { career: 3, love: 1, finance: 3, luck: 1 } },\n                        { text: "金色 - 成功与财富", values: { career: 3, love: 2, finance: 3, luck: 2 } }\n                    ]\n                },\n                {\n                    question: "在社交场合中，你通常会？",\n                    options: [\n                        { text: "成为众人的焦点", values: { career: 2, love: 3, finance: 1, luck: 2 } },\n                        { text: "与少数人深入交流", values: { career: 1, love: 3, finance: 2, luck: 1 } },\n                        { text: "观察周围的人和环境", values: { career: 3, love: 1, finance: 2, luck: 3 } },\n                        { text: "寻找安静的角落独处", values: { career: 1, love: 1, finance: 3, luck: 1 } }\n                    ]\n                },\n                {\n                    question: "面对困难时，你的第一反应是？",\n                    options: [\n                        { text: "寻找解决方案", values: { career: 3, love: 2, finance: 3, luck: 1 } },\n                        { text: "寻求帮助和支持", values: { text: { career: 1, love: 3, finance: 1, luck: 2 } }},\n                        { text: "保持冷静，等待时机", values: { career: 2, love: 1, finance: 2, luck: 3 } },\n                        { text: "接受并适应变化", values: { career: 2, love: 2, finance: 2, luck: 3 } }\n                    ]\n                },\n                {\n                    question: "你最向往的生活方式是？",\n                    options: [\n                        { text: "充满挑战和冒险", values: { career: 3, love: 2, finance: 1, luck: 2 } },\n                        { text: "稳定安逸的日常", values: { career: 1, love: 3, finance: 3, luck: 1 } },\n                        { text: "不断学习和成长", values: { career: 3, love: 1, finance: 2, luck: 2 } },\n                        { text: "帮助他人实现价值", values: { career: 2, love: 3, finance: 1, luck: 3 } }\n                    ]\n                }\n            ],\n            \n            results: {\n                career: {\n                    high: {\n                        title: "事业之星",\n                        icon: "🌟",\n                        description: "命运女神眷顾你的职业生涯。你将在事业上取得显著成就，成为行业内的领军人物。你的领导才能和创新思维将为你打开成功的大门。建议你现在开始规划长远目标，宇宙的能量正在为你铺平道路。",\n                        luck: 4\n                    },\n                    medium: {\n                        title: "平稳发展",\n                        icon: "📈",\n                        description: "你的职业道路将稳步前进。虽然不会一夜成名，但你扎实的努力将逐渐积累成果。耐心是此刻的关键，持续学习和成长将为你带来意想不到的机遇。保持专注，你的努力终将得到回报。",\n                        luck: 3\n                    },\n                    low: {\n                        title: "转变之路",\n                        icon: "🔄",\n                        description: "你的职业正处于转型期。这是探索新方向的绝佳时机，虽然可能会有一些不确定性，但这也是你重新定位自己的机会。不要害怕改变，宇宙正在引导你走向更适合的道路。勇敢尝试，你会发现隐藏的潜能。",\n                        luck: 2\n                    }\n                },\n                love: {\n                    high: {\n                        title: "缘分天成",\n                        icon: "💕",\n                        description: "爱情星象格外明亮，预示着一段美好的情感旅程即将开始。无论是单身还是已有伴侣，你都将感受到爱的温暖。宇宙已为你安排了完美的相遇，保持开放的心态，真爱将在意想不到的时刻降临。",\n                        luck: 4\n                    },\n                    medium: {\n                        title: "情感稳定",\n                        icon: "❤️",\n                        description: "你的感情生活将保持平衡和谐。现有关系将进入深化阶段，双方的理解和信任会进一步增强。单身的朋友可能会遇到有趣的人，但目前还不需要急于决定。享受当下，让感情自然发展。",\n                        luck: 3\n                    },\n                    low: {\n                        title: "反思成长",\n                        icon: "💭",\n                        description: "现在是自我反思的时期。过去的情感经历带来了重要的人生教训。不要急于投入新关系，先学会与自己相处。这段独处时光将帮助你更清楚地了解自己在亲密关系中的需求和期望。",\n                        luck: 2\n                    }\n                },\n                finance: {\n                    high: {\n                        title: "财源广进",\n                        icon: "💰",\n                        description: "财富星象异常耀眼，预示着财务上的丰收期。你可能会迎来意想不到的金钱增长，或许是投资回报、晋升加薪或意外之财。保持开放和慷慨的心态，财富的能量会自然流动到你身边。",\n                        luck: 4\n                    },\n                    medium: {\n                        title: "稳步积累",\n                        icon: "🏦",\n                        description: "财务状况将保持稳定增长。你会迎来不错的收入机会，但仍需要谨慎规划。现在是建立理财习惯的好时机，合理预算和明智投资将为你的未来打下坚实基础。耐心是获取财富的关键。",\n                        luck: 3\n                    },\n                    low: {\n                        title: "调整策略",\n                        icon: "📊",\n                        description: "财务方面可能需要一些调整。现在是重新审视支出和收入的好时机。可能需要改变某些消费习惯或寻找额外的收入来源。不要气馁，这只是暂时的挑战，学习新的理财策略将帮助你改善状况。",\n                        luck: 2\n                    }\n                },\n                luck: {\n                    high: {\n                        title: "幸运爆棚",\n                        icon: "🍀",\n                        description: "幸运星正闪耀在你生命的各个领域。你可能会遇到贵人相助，事情进展出乎意料地顺利。保持积极乐观的心态，相信宇宙的指引。现在是尝试新事物、追求梦想的最佳时机。幸运会向你微笑。",\n                        luck: 5\n                    },\n                    medium: {\n                        title: "顺势而为",\n                        icon: "🌈",\n                        description: "整体运势平稳向好。虽然不会事事顺心，但大多数情况下事情会朝有利的方向发展。顺应宇宙的节奏，在机会出现时果断把握。保持灵活变通的态度，好运将会与你不期而遇。",\n                        luck: 3\n                    },\n                    low: {\n                        title: "积累能量",\n                        icon: "⚡",\n                        description: "现在是积累能量和智慧的时候。生活可能充满挑战，但这些都是成长必经的考验。不要气馁，这些都是宇宙在帮助你变得更强大。耐心等待，当时机成熟时，你的努力将得到丰厚的回报。",\n                        luck: 2\n                    }\n                }\n            }\n        };\n        \n        // 游戏状态\n        let currentQuestionIndex = 0;\n        let answers = {\n            career: 0,\n            love: 0,\n            finance: 0,\n            luck: 0\n        };\n        \n        // DOM 元素\n        const startScreen = document.querySelector('.start-screen');\n        const startButton = document.getElementById('startButton');\n        const questionContainer = document.getElementById('questionContainer');\n        const questionText = document.getElementById('questionText');\n        const optionsContainer = document.getElementById('optionsContainer');\n        const resultContainer = document.getElementById('resultContainer');\n        const progressBar = document.getElementById('progressBar');\n        const restartButton = document.getElementById('restartButton');\n        const fortuneTellerText = document.querySelector('.fortune-teller-text');\n        \n        // 初始化游戏\n        function initGame() {\n            startButton.addEventListener('click', startGame);\n            restartButton.addEventListener('click', restartGame);\n        }\n        \n        // 开始游戏\n        function startGame() {\n            startScreen.style.display = 'none';\n            questionContainer.style.display = 'block';\n            currentQuestionIndex = 0;\n            answers = {\n                career: 0,\n                love: 0,\n                finance: 0,\n                luck: 0\n            };\n            showQuestion();\n        }\n        \n        // 显示问题\n        function showQuestion() {\n            const question = gameData.questions[currentQuestionIndex];\n            questionText.textContent = question.question;\n            optionsContainer.innerHTML = '';\n            \n            question.options.forEach((option, index) => {\n                const optionElement = document.createElement('div');\n                optionElement.className = 'option';\n                optionElement.textContent = option.text;\n                optionElement.setAttribute('tabindex', '0');\n                \n                optionElement.addEventListener('click', () => selectOption(option));\n                optionElement.addEventListener('keydown', (e) => {\n                    if (e.key === 'Enter' || e.key === ' ') {\n                        e.preventDefault();\n                        selectOption(option);\n                    }\n                });\n                \n                optionsContainer.appendChild(optionElement);\n            });\n            \n            updateProgress();\n        }\n        \n        // 更新进度条\n        function updateProgress() {\n            const progress = ((currentQuestionIndex + 1) / gameData.questions.length) * 100;\n            progressBar.style.width = `${progress}%`;\n        }\n        \n        // 选择答案\n        function selectOption(option) {\n            // 更新分数\n            for (const [key, value] of Object.entries(option.values)) {\n                answers[key] += value;\n            }\n            \n            // 移动到下一个问题或显示结果\n            currentQuestionIndex++;\n            if (currentQuestionIndex < gameData.questions.length) {\n                setTimeout(() => showQuestion(), 300);\n            } else {\n                setTimeout(showResult, 500);\n            }\n        }\n        \n        // 显示结果\n        function showResult() {\n            questionContainer.style.display = 'none';\n            resultContainer.style.display = 'block';\n            \n            // 计算各领域得分并选择结果\n            const resultTypes = ['career', 'love', 'finance', 'luck'];\n            let resultHTML = '<h2>你的命运解读：</h2><br>';\n            \n            resultTypes.forEach(type => {\n                const score = answers[type];\n                let level;\n                \n                if (type === 'luck') {\n                    level = score >= 10 ? 'high' : score >= 6 ? 'medium' : 'low';\n                } else {\n                    level = score >= 8 ? 'high' : score >= 4 ? 'medium' : 'low';\n                }\n                \n                const result = gameData.results[type][level];\n                resultHTML += `\n                    <div style="margin-bottom: 30px;">\n                        <div style="display: flex; align-items: center; justify-content: center; margin-bottom: 15px;">\n                            <span style="font-size: 2.5em; margin-right: 15px;">${result.icon}</span>\n                            <h3 style="font-size: 1.8em;">${result.title}</h3>\n                        </div>\n                        <p style="font-size: 1.1em; line-height: 1.6; text-align: center;">${result.description}</p>\n                    </div>\n                `;\n            });\n            \n            // 计算总体幸运值\n            const totalLuck = Math.round((answers.luck / 15) * 5);\n            const stars = '⭐'.repeat(totalLuck) + '☆'.repeat(5 - totalLuck);\n            \n            document.getElementById('resultImage').textContent = '🔮';\n            document.getElementById('resultText').innerHTML = resultHTML;\n            document.getElementById('stars').textContent = stars;\n            \n            // 更新算命师文字\n            fortuneTellerText.textContent = "神秘的能量已融入你生命的画卷...记住，命运是你自己创造的。";\n        }\n        \n        // 重新开始游戏\n        function restartGame() {\n            resultContainer.style.display = 'none';\n            startScreen.style.display = 'block';\n            progressBar.style.width = '0%';\n            fortuneTellerText.textContent = "我是一位古老的算命师，能够窥见你命运的轮盘...";\n        }\n        \n        // 启动游戏\n        document.addEventListener('DOMContentLoaded', initGame);\n    </script>\n</body>\n</html>			\N	\N	\N	2025-11-28 11:30:30.684	2025-11-28 11:36:25.734	生命	t
