              <div class="color-picker" id="shoe-colors">\n                    <div class="color-option active" style="background-color: #333" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #ff0000" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #00ff00" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #0000ff" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #ffff00" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #ff00ff" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #00ffff" data-target="shoe" data-attr="fill"></div>\n                    <div class="color-option" style="background-color: #ffa500" data-target="shoe" data-attr="fill"></div>\n                </div>\n                \n                <div class="items-grid" id="shoe-styles" style="margin-top: 1rem;">\n                    <div class="item active" data-target="shoe" data-svg="sneaker">\n                        <svg width="50" height="20" viewBox="0 0 50 20">\n                            <ellipse cx="25" cy="10" rx="22" ry="8" fill="#333"/>\n                            <rect x="10" y="5" width="30" height="8" rx="3" fill="#666"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="shoe" data-svg="heeled">\n                        <svg width="50" height="25" viewBox="0 0 50 25">\n                            <path d="M10 15 L8 20 L20 20 L22 15 Z" fill="#333"/>\n                            <path d="M30 15 L28 20 L42 20 L40 15 Z" fill="#333"/>\n                            <ellipse cx="16" cy="10" rx="10" ry="5" fill="#333"/>\n                            <ellipse cx="34" cy="10" rx="10" ry="5" fill="#333"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="shoe" data-svg="boots">\n                        <svg width="50" height="25" viewBox="0 0 50 25">\n                            <rect x="10" y="8" width="30" height="12" rx="5" fill="#333"/>\n                            <rect x="8" y="5" width="34" height="6" rx="3" fill="#666"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="shoe" data-svg="sandals">\n                        <svg width="50" height="25" viewBox="0 0 50 25">\n                            <ellipse cx="25" cy="10" rx="22" ry="8" fill="none" stroke="#333" stroke-width="2"/>\n                            <line x1="25" y1="2" x2="25" y2="18" stroke="#333" stroke-width="2"/>\n                            <line x1="15" y1="10" x2="35" y2="10" stroke="#333" stroke-width="2"/>\n                        </svg>\n                    </div>\n                </div>\n            </div>\n            \n            <div class="category">\n                <div class="category-title">\n                    <span>任芊羽配饰</span>\n                </div>\n                <div class="items-grid" id="accessories-grid">\n                    <div class="item" data-target="accessories" data-svg="hat">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <path d="M10 20 L40 20 L45 10 L5 10 Z" fill="#8b4513" stroke="#333" stroke-width="1"/>\n                            <rect x="20" y="10" width="10" height="5" fill="#8b4513" stroke="#333" stroke-width="1"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="accessories" data-svg="glasses">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <circle cx="18" cy="15" r="8" fill="none" stroke="#333" stroke-width="2"/>\n                            <circle cx="32" cy="15" r="8" fill="none" stroke="#333" stroke-width="2"/>\n                            <line x1="26" y1="15" x2="24" y2="15" stroke="#333" stroke-width="2"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="accessories" data-svg="necklace">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <path d="M25 20 L20 30 L30 30 Z" fill="#ffd700" stroke="#333" stroke-width="1"/>\n                            <circle cx="25" cy="20" r="3" fill="#ffd700" stroke="#333" stroke-width="1"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="accessories" data-svg="watch">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <rect x="32" y="12" width="8" height="12" rx="2" fill="#333"/>\n                            <circle cx="36" cy="18" r="3" fill="none" stroke="#fff" stroke-width="1"/>\n                            <line x1="36" y1="18" x2="36" y2="15" stroke="#fff" stroke-width="1"/>\n                            <line x1="36" y1="18" x2="38" y2="18" stroke="#fff" stroke-width="1"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="accessories" data-svg="earrings">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <circle cx="10" cy="20" r="4" fill="#ffd700" stroke="#333" stroke-width="1"/>\n                            <circle cx="40" cy="20" r="4" fill="#ffd700" stroke="#333" stroke-width="1"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="accessories" data-svg="none">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <line x1="10" y1="10" x2="40" y2="20" stroke="#ccc" stroke-width="1" stroke-dasharray="5,5"/>\n                            <text x="25" y="15" text-anchor="middle" fill="#ccc">无</text>\n                        </svg>\n                    </div>\n                </div>\n            </div>\n            \n            <div class="category">\n                <div class="category-title">\n                    <span>任芊羽装饰</span>\n                </div>\n                <div class="items-grid" id="decorations-grid">\n                    <div class="item" data-target="decorations" data-svg="flower">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <circle cx="25" cy="15" r="5" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <circle cx="25" cy="8" r="4" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <circle cx="25" cy="22" r="4" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <circle cx="18" cy="15" r="4" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <circle cx="32" cy="15" r="4" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <circle cx="25" cy="15" r="3" fill="#ffd700"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="decorations" data-svg="star">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <path d="M25 5 L28 15 L38 15 L30 22 L33 32 L25 25 L17 32 L20 22 L12 15 L22 15 Z" fill="#ffd700" stroke="#333" stroke-width="1"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="decorations" data-svg="heart">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <path d="M25 25 C25 25, 10 15, 10 10 C10 5, 15 0, 20 5 C22 7, 25 10, 25 10 C25 10, 28 7, 30 5 C35 0, 40 5, 40 10 C40 15, 25 25, 25 25 Z" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="decorations" data-svg="bow">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <circle cx="20" cy="15" r="5" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <circle cx="30" cy="15" r="5" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                            <rect x="22" y="14" width="6" height="2" fill="#ff69b4"/>\n                        </svg>\n                    </div>\n                    <div class="item" data-target="decorations" data-svg="none">\n                        <svg width="50" height="30" viewBox="0 0 50 30">\n                            <line x1="10" y1="10" x2="40" y2="20" stroke="#ccc" stroke-width="1" stroke-dasharray="5,5"/>\n                            <text x="25" y="15" text-anchor="middle" fill="#ccc">无</text>\n                        </svg>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </main>\n    \n    <div class="notification" id="notification">\n        图片已保存到下载文件夹！\n    </div>\n    \n    <script>\n        // 获取元素\n        \n    </script>\n</body>\n</html>	* {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n            font-family: 'Arial', sans-serif;\n        }\n        \n        body {\n            background-color: #f8f9fa;\n            display: flex;\n            flex-direction: column;\n            min-height: 100vh;\n        }\n        \n        header {\n            background-color: #fff;\n            padding: 1rem;\n            box-shadow: 0 2px 5px rgba(0,0,0,0.1);\n        }\n        \n        h1 {\n            text-align: center;\n            color: #333;\n            font-size: 1.8rem;\n        }\n        \n        main {\n            flex: 1;\n            display: flex;\n            flex-wrap: wrap;\n            padding: 1rem;\n            gap: 1rem;\n            max-width: 1400px;\n            margin: 0 auto;\n            width: 100%;\n        }\n        \n        .character-display {\n            flex: 1 1 300px;\n            background-color: #fff;\n            border-radius: 10px;\n            box-shadow: 0 3px 10px rgba(0,0,0,0.1);\n            padding: 1.5rem;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n        }\n        \n        .character-container {\n            width: 300px;\n            height: 400px;\n            position: relative;\n            margin: 1rem 0;\n        }\n        \n        .character {\n            width: 100%;\n            height: 100%;\n        }\n        \n        .controls {\n            flex: 1 1 300px;\n            display: flex;\n            flex-direction: column;\n            gap: 1rem;\n        }\n        \n        .category {\n            background-color: #fff;\n            border-radius: 10px;\n            box-shadow: 0 3px 10px rgba(0,0,0,0.1);\n            padding: 1rem;\n        }\n        \n        .category-title {\n            font-size: 1.2rem;\n            margin-bottom: 0.8rem;\n            color: #444;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n        }\n        \n        .color-picker {\n            display: flex;\n            gap: 0.5rem;\n            flex-wrap: wrap;\n            margin-bottom: 1rem;\n        }\n        \n        .color-option {\n            width: 30px;\n            height: 30px;\n            border-radius: 50%;\n            cursor: pointer;\n            border: 2px solid transparent;\n            transition: transform 0.2s;\n        }\n        \n        .color-option:hover {\n            transform: scale(1.1);\n        }\n        \n        .color-option.active {\n            border-color: #333;\n            transform: scale(1.15);\n        }\n        \n        .items-grid {\n            display: grid;\n            grid-template-columns: repeat(auto-fill, minmax(60px, 1fr));\n            gap: 0.5rem;\n        }\n        \n        .item {\n            width: 60px;\n            height: 60px;\n            border-radius: 8px;\n            cursor: pointer;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            background-color: #f5f5f5;\n            transition: transform 0.2s;\n            border: 2px solid transparent;\n        }\n        \n        .item:hover {\n            transform: scale(1.05);\n            background-color: #f0f0f0;\n        }\n        \n        .item.active {\n            border-color: #4CAF50;\n        }\n        \n        .action-buttons {\n            display: flex;\n            gap: 0.5rem;\n            margin-top: 1rem;\n        }\n        \n        button {\n            padding: 0.8rem 1.2rem;\n            border: none;\n            border-radius: 6px;\n            background-color: #4CAF50;\n            color: white;\n            cursor: pointer;\n            font-size: 1rem;\n            transition: background-color 0.3s;\n        }\n        \n        button:hover {\n            background-color: #45a049;\n        }\n        \n        .reset-button {\n            background-color: #ff6b6b;\n        }\n        \n        .reset-button:hover {\n            background-color: #ff5252;\n        }\n        \n        .save-button {\n            background-color: #3498db;\n        }\n        \n        .save-button:hover {\n            background-color: #2980b9;\n        }\n        \n        .notification {\n            position: fixed;\n            bottom: 20px;\n            right: 20px;\n            background-color: #4CAF50;\n            color: white;\n            padding: 1rem 1.5rem;\n            border-radius: 6px;\n            box-shadow: 0 3px 10px rgba(0,0,0,0.2);\n            transform: translateY(100px);\n            opacity: 0;\n            transition: all 0.3s;\n        }\n        \n        .notification.show {\n            transform: translateY(0);\n            opacity: 1;\n        }\n        \n        @media (max-width: 768px) {\n            main {\n                flex-direction: column;\n            }\n            \n            .character-container {\n                width: 200px;\n                height: 300px;\n            }\n        }	const character = document.querySelector('.character');\n        const skinColors = document.querySelectorAll('#skin-colors .color-option');\n        const bodyColors = document.querySelectorAll('#body-colors .color-option');\n        const shoeColors = document.querySelectorAll('#shoe-colors .color-option');\n        const hairStyles = document.querySelectorAll('#hair-styles .item');\n        const shoeStyles = document.querySelectorAll('#shoe-styles .item');\n        const accessoriesGrid = document.querySelectorAll('#accessories-grid .item');\n        const decorationsGrid = document.querySelectorAll('#decorations-grid .item');\n        const saveBtn = document.getElementById('save-btn');\n        const resetBtn = document.getElementById('reset-btn');\n        const notification = document.getElementById('notification');\n        \n        // 存储当前选择的样式\n        const currentStyles = {\n            skinColor: '#fdbcb4',\n            bodyColor: '#6495ed',\n            shoeColor: '#333333',\n            shoeStyle: 'sneaker',\n            hairStyle: 'default',\n            accessories: 'none',\n            decorations: 'none'\n        };\n        \n        // 创建SVG样式对象\n        const hairStylesData = {\n            default: `\n                <path d="M90 80 Q90 40 150 40 Q210 40 210 80" fill="#8b4513" stroke="#333" stroke-width="2"/>\n                <circle cx="120" cy="60" r="8" fill="#8b4513"/>\n                <circle cx="150" cy="50" r="10" fill="#8b4513"/>\n                <circle cx="180" cy="60" r="8" fill="#8b4513"/>\n            `,\n            short: `\n                <rect x="90" y="80" width="120" height="15" fill="#333" stroke="#333" stroke-width="2"/>\n            `,\n            long: `\n                <path d="M90 80 Q90 40 150 40 Q210 40 210 80 L215 125 Q210 120 205 122 Q200 120 195 122 Q190 120 185 122 Q180 120 175 122 Q170 120 165 122 Q160 120 155 122 Q150 120 145 122 Q140 120 135 122 Q130 120 125 122 Q120 120 115 125 Z" fill="#4b0082" stroke="#333" stroke-width="2"/>\n            `,\n            curly: `\n                <circle cx="115" cy="80" r="12" fill="#ff69b4" stroke="#333" stroke-width="2"/>\n                <circle cx="150" cy="75" r="12" fill="#ff69b4" stroke="#333" stroke-width="2"/>\n                <circle cx="185" cy="80" r="12" fill="#ff69b4" stroke="#333" stroke-width="2"/>\n            `,\n            ponytail: `\n                <path d="M115 85 Q115 65 150 65 Q185 65 185 85 L190 95 Q170 85 150 87 Q130 85 110 95 Z" fill="#333" stroke="#333" stroke-width="2"/>\n                <circle cx="150" cy="95" r="12" fill="#333" stroke="#333" stroke-width="2"/>\n            `,\n            bald: `\n                <circle cx="150" cy="80" r="25" fill="none" stroke="#333" stroke-width="2"/>\n            `\n        };\n        \n        const shoeStylesData = {\n            sneaker: `\n                <g class="shoes-container">\n                    <ellipse class="left-shoe" cx="132" cy="370" rx="20" ry="10" fill="#333"/>\n                    <ellipse class="right-shoe" cx="168" cy="370" rx="20" ry="10" fill="#333"/>\n                    <rect class="left-shoe-detail" x="122" y="365" width="20" height="8" rx="3" fill="#666"/>\n                    <rect class="right-shoe-detail" x="158" y="365" width="20" height="8" rx="3" fill="#666"/>\n                </g>\n            `,\n            heeled: `\n                <g class="shoes-container">\n                    <path class="left-shoe" d="M122 370 L120 380 L132 380 L134 370 Z" fill="#333"/>\n                    <path class="right-shoe" d="M166 370 L164 380 L176 380 L178 370 Z" fill="#333"/>\n                    <ellipse class="left-shoe" cx="126" cy="365" rx="10" ry="8" fill="#333"/>\n                    <ellipse class="right-shoe" cx="174" cy="365" rx="10" ry="8" fill="#333"/>\n                </g>\n            `,\n            boots: `\n                <g class="shoes-container">\n                    <rect class="left-shoe" x="122" y="360" width="20" height="18" rx="5" fill="#333"/>\n                    <rect class="right-shoe" x="158" y="360" width="20" height="18" rx="5" fill="#333"/>\n                    <rect class="left-shoe" x="120" y="355" width="24" height="8" rx="3" fill="#666"/>\n                    <rect class="right-shoe" x="156" y="355" width="24" height="8" rx="3" fill="#666"/>\n                </g>\n            `,\n            sandals: `\n                <g class="shoes-container">\n                    <ellipse class="left-shoe" cx="132" cy="370" rx="20" ry="10" fill="none" stroke="#333" stroke-width="3"/>\n                    <ellipse class="right-shoe" cx="168" cy="370" rx="20" ry="10" fill="none" stroke="#333" stroke-width="3"/>\n                    <line class="left-shoe" x1="132" y1="360" x2="132" y2="380" stroke="#333" stroke-width="2"/>\n                    <line class="right-shoe" x1="168" y1="360" x2="168" y2="380" stroke="#333" stroke-width="2"/>\n                    <line class="left-shoe" x1="122" y1="370" x2="142" y2="370" stroke="#333" stroke-width="2"/>\n                    <line class="right-shoe" x1="158" y1="370" x2="178" y2="370" stroke="#333" stroke-width="2"/>\n                </g>\n            `\n        };\n        \n        const accessoriesData = {\n            hat: `\n                <path d="M90 100 L210 100 L215 70 L85 70 Z" fill="#8b4513" stroke="#333" stroke-width="2"/>\n                <rect x="140" y="70" width="20" height="10" fill="#8b4513" stroke="#333" stroke-width="2"/>\n            `,\n            glasses: `\n                <circle cx="130" cy="90" r="12" fill="none" stroke="#333" stroke-width="2"/>\n                <circle cx="170" cy="90" r="12" fill="none" stroke="#333" stroke-width="2"/>\n                <line x1="142" y1="90" x2="158" y2="90" stroke="#333" stroke-width="2"/>\n            `,\n            necklace: `\n                <path d="M150 160 L145 180 L155 180 Z" fill="#ffd700" stroke="#333" stroke-width="2"/>\n                <circle cx="150" cy="160" r="5" fill="#ffd700" stroke="#333" stroke-width="2"/>\n            `,\n            watch: `\n                <rect x="210" y="165" width="16" height="24" rx="4" fill="#333" stroke="#333" stroke-width="2"/>\n                <circle cx="218" cy="177" r="6" fill="none" stroke="#fff" stroke-width="2"/>\n                <line x1="218" y1="177" x2="218" y2="173" stroke="#fff" stroke-width="1"/>\n                <line x1="218" y1="177" x2="222" y2="177" stroke="#fff" stroke-width="1"/>\n            `,\n            earrings: `\n                <circle cx="90" cy="95" r="6" fill="#ffd700" stroke="#333" stroke-width="2"/>\n                <circle cx="210" cy="95" r="6" fill="#ffd700" stroke="#333" stroke-width="2"/>\n            `\n        };\n        \n        const decorationsData = {\n            flower: `\n                <g transform="translate(220, 160)">\n                    <circle cx="0" cy="0" r="8" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <circle cx="0" cy="-10" r="6" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <circle cx="0" cy="10" r="6" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <circle cx="-10" cy="0" r="6" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <circle cx="10" cy="0" r="6" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <circle cx="0" cy="0" r="5" fill="#ffd700"/>\n                </g>\n            `,\n            star: `\n                <g transform="translate(220, 160)">\n                    <path d="M0,-12 L3,-3 L12,-3 L5,3 L8,12 L0,6 L-8,12 L-5,3 L-12,-3 L-3,-3 Z" fill="#ffd700" stroke="#333" stroke-width="1"/>\n                </g>\n            `,\n            heart: `\n                <g transform="translate(220, 170)">\n                    <path d="M0,10 C0,10,-15,0,-15,-5 C-15,-10,-10,-15,-5,-10 C0,-5,0,0,0,0 C0,0,0,-5,5,-10 C10,-15,15,-10,15,-5 C15,0,0,10,0,10 Z" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                </g>\n            `,\n            bow: `\n                <g transform="translate(220, 165)">\n                    <ellipse cx="-8" cy="0" rx="10" ry="8" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <ellipse cx="8" cy="0" rx="10" ry="8" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                    <rect x="-3" y="-2" width="6" height="4" fill="#ff69b4" stroke="#333" stroke-width="1"/>\n                </g>\n            `\n        };\n        \n        // 事件监听器\n        skinColors.forEach(option => {\n            option.addEventListener('click', function() {\n                skinColors.forEach(opt => opt.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = this.dataset.target;\n                const attr = this.dataset.attr;\n                const color = this.style.backgroundColor;\n                \n                document.getElementById(target).setAttribute(attr, color);\n                currentStyles.skinColor = color;\n            });\n        });\n        \n        bodyColors.forEach(option => {\n            option.addEventListener('click', function() {\n                bodyColors.forEach(opt => opt.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = this.dataset.target;\n                const attr = this.dataset.attr;\n                const color = this.style.backgroundColor;\n                \n                document.getElementById(target).setAttribute(attr, color);\n                document.getElementById('left-leg').setAttribute(attr, color);\n                document.getElementById('right-leg').setAttribute(attr, color);\n                currentStyles.bodyColor = color;\n            });\n        });\n        \n        shoeColors.forEach(option => {\n            option.addEventListener('click', function() {\n                shoeColors.forEach(opt => opt.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = this.dataset.target;\n                const color = this.style.backgroundColor;\n                \n                // 更新左右脚的颜色\n                document.getElementById('left-shoe').setAttribute('fill', color);\n                document.getElementById('right-shoe').setAttribute('fill', color);\n                currentStyles.shoeColor = color;\n            });\n        });\n        \n        hairStyles.forEach(item => {\n            item.addEventListener('click', function() {\n                hairStyles.forEach(i => i.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = this.dataset.target;\n                const style = this.dataset.svg;\n                const svg = document.getElementById(target);\n                \n                if (style !== 'none') {\n                    svg.innerHTML = hairStylesData[style];\n                    currentStyles.hairStyle = style;\n                }\n            });\n        });\n        \n        shoeStyles.forEach(item => {\n            item.addEventListener('click', function() {\n                shoeStyles.forEach(i => i.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = 'shoe';\n                const style = this.dataset.svg;\n                \n                // 查找并替换鞋子的SVG\n                const shoesContainer = document.createElementNS('http://www.w3.org/2000/svg', 'g');\n                shoesContainer.innerHTML = shoeStylesData[style];\n                \n                // 获取鞋子容器\n                const existingShoes = document.querySelector('.shoes-container');\n                if (existingShoes) {\n                    existingShoes.parentNode.replaceChild(shoesContainer, existingShoes);\n                } else {\n                    document.querySelector('.character').appendChild(shoesContainer);\n                }\n                \n                // 设置当前颜色\n                const leftShoe = shoesContainer.querySelector('.left-shoe');\n                const rightShoe = shoesContainer.querySelector('.right-shoe');\n                if (leftShoe && rightShoe) {\n                    leftShoe.setAttribute('fill', currentStyles.shoeColor);\n                    rightShoe.setAttribute('fill', currentStyles.shoeColor);\n                }\n                \n                currentStyles.shoeStyle = style;\n            });\n        });\n        \n        accessoriesGrid.forEach(item => {\n            item.addEventListener('click', function() {\n                accessoriesGrid.forEach(i => i.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = this.dataset.target;\n                const style = this.dataset.svg;\n                const svg = document.getElementById(target);\n                \n                svg.innerHTML = '';\n                if (style !== 'none') {\n                    svg.innerHTML = accessoriesData[style];\n                }\n                currentStyles.accessories = style;\n            });\n        });\n        \n        decorationsGrid.forEach(item => {\n            item.addEventListener('click', function() {\n                decorationsGrid.forEach(i => i.classList.remove('active'));\n                this.classList.add('active');\n                \n                const target = document.getElementById('decorations');\n                const style = this.dataset.svg;\n                \n                target.innerHTML = '';\n                if (style !== 'none') {\n                    target.innerHTML = decorationsData[style];\n                }\n                currentStyles.decorations = style;\n            });\n        });\n        \n        // 保存功能\n        saveBtn.addEventListener('click', function() {\n            const svgData = new XMLSerializer().serializeToString(character);\n            const svgBlob = new Blob([svgData], {type: 'image/svg+xml;charset=utf-8'});\n            const url = URL.createObjectURL(svgBlob);\n            \n            const canvas = document.createElement('canvas');\n            const ctx = canvas.getContext('2d');\n            canvas.width = 300;\n            canvas.height = 400;\n            \n            const img = new Image();\n            img.onload = function() {\n                ctx.fillStyle = '#f8f9fa';\n                ctx.fillRect(0, 0, canvas.width, canvas.height);\n                ctx.drawImage(img, 0, 0);\n                \n                canvas.toBlob(function(blob) {\n                    const link = document.createElement('a');\n                    link.download = 'my-character-design.png';\n                    link.href = URL.createObjectURL(blob);\n                    link.click();\n                    \n                    // 显示通知\n                    notification.classList.add('show');\n                    setTimeout(() => {\n                        notification.classList.remove('show');\n                    }, 3000);\n                });\n            };\n            img.src = url;\n        });\n        \n        // 重置功能\n        resetBtn.addEventListener('click', function() {\n            // 重置颜色选择\n            skinColors.forEach(opt => opt.classList.remove('active'));\n            bodyColors.forEach(opt => opt.classList.remove('active'));\n            shoeColors.forEach(opt => opt.classList.remove('active'));\n            hairStyles.forEach(i => i.